-- BBB: Understanding the Bible (4 topics)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('bbb00000-e29b-41d4-a716-446655440001', 'hi',
   'बाइबल हमें कैसे मिली',
   'परमेश्वर ने अपना वचन एक अनोखे तरीके से दिया — 40 से अधिक लेखकों ने, 1,500 वर्षों की अवधि में, अलग-अलग भाषाओं और संस्कृतियों में लिखा — और फिर भी पूरी बाइबल एक सुसंगत संदेश रखती है। इस अध्ययन में जानें कि "प्रेरणा" का क्या अर्थ है: परमेश्वर ने लेखकों के व्यक्तित्व और शब्दों का उपयोग करते हुए बिना त्रुटि के अपना वचन दिया। यह भी समझें कि पुरानी और नई नियम की पुस्तकें कैसे एकत्रित की गईं, कौन-सी पुस्तकें क्यों शामिल की गईं, और इस चुनाव का आधार क्या था। साथ ही जानें कि सदियों में नकल करते हुए भी बाइबल का मूल पाठ कैसे सुरक्षित रहा। यह ज्ञान आपके बाइबल पढ़ने में गहरा विश्वास जोड़ता है और यह भरोसा देता है कि हम जो पढ़ते हैं वह वास्तव में परमेश्वर का अधिकारिक वचन है।',
   'Foundations of Faith'),

  ('bbb00000-e29b-41d4-a716-446655440001', 'ml',
   'ബൈബിൾ നമുക്ക് എങ്ങനെ ലഭിച്ചു',
   'ദൈവം തന്റെ വചനം ഒരു അദ്ഭുത പ്രക്രിയ വഴി നൽകി — 40-ലധികം വ്യത്യസ്ത എഴുത്തുകാർ, 1,500 വർഷ കാലയളവ്, പല ഭാഷകളും സംസ്കാരങ്ങളും — എന്നിട്ടും ഒരേ ഐക്യ ബോധം ഉള്ള ഒരു ഗ്രന്ഥം. "ദൈവ നിശ്വാസം" (Inspiration) എന്നതിന്റെ അർത്ഥം: ദൈവം എഴുത്തുകാരുടെ വ്യക്തിത്വവും ഭാഷയും ഉപയോഗിച്ച്, തെറ്റില്ലാതെ, ഉദ്ദേശ ശ്രദ്ധോടെ തന്റെ വചനം നൽകി. ഏത് പുസ്തകങ്ങൾ ബൈബിളിൽ ഉൾക്കൊള്ളിക്കണം എന്ന് ആദ്യ സഭ ഏതടിസ്ഥാനത്തിൽ — അപ്പൊസ്തലിക ബന്ധം, ആന്തരിക ഐക്യം, സഭ ഉപയോഗം — ഇതിൽ തീരുമാനിച്ചു. നൂറ്റാണ്ടുകൾ പകർത്തിയെഴുതിയിട്ടും ബൈബിൾ മൂല ശ്രദ്ധ ഇന്നും സംരക്ഷിക്കപ്പെട്ടതെങ്ങനെ എന്ന് പഠിക്കുക. ഇന്ന് നാം ആശ്രയിക്കുന്ന ബൈബിൾ ദൈവ വചനം ആണ് എന്ന ഉറ ബോദ്ധ്യം ഈ അറിവ് നൽകുന്നു.',
   'Foundations of Faith'),

  ('bbb00000-e29b-41d4-a716-446655440002', 'hi',
   'बाइबल के साहित्यिक प्रकार',
   'बाइबल एक किताब नहीं बल्कि 66 किताबों का संग्रह है — जिनमें इतिहास, कविता, भविष्यवाणी, ज्ञान साहित्य, पत्रियाँ और सर्वनाश साहित्य शामिल हैं। हर साहित्यिक प्रकार के अपने नियम और पढ़ने का तरीका होता है — उत्पत्ति की ऐतिहासिक कथा को वैसे नहीं पढ़ते जैसे भजन की कविता को। अगर हम प्रकार को नहीं समझते, तो हम लेखक का असली मतलब गलत समझ सकते हैं या बाइबल के बारे में झूठे विरोधाभास देख सकते हैं। इस अध्ययन में जानें कि प्रत्येक प्रकार में परमेश्वर कैसे संचार करते हैं, और यीशु ने खुद इन सभी प्रकारों को कैसे उपयोग किया। सही साहित्यिक समझ बाइबल अध्ययन को गहरा, सटीक और जीवन बदलने वाला बनाती है।',
   'Foundations of Faith'),

  ('bbb00000-e29b-41d4-a716-446655440002', 'ml',
   'ബൈബിൾ ശൈലികൾ മനസ്സിലാക്കൽ',
   'ബൈബിൾ 66 പുസ്തകങ്ങളുടെ ഒരു ശേഖരം — ചരിത്രം, കവിത, പ്രവചനം, ജ്ഞാന ഗ്രന്ഥം, ലേഖനങ്ങൾ, ദർശന ഗ്രന്ഥം — ഓരോന്നും വ്യത്യസ്ത ശൈലിയിൽ ദൈവ ആശയ വിനിമയം ചെയ്യുന്നു. ഓരോ ശൈലിക്കും വ്യത്യസ്ത വായനാ നിയമങ്ങൾ — ഉൽപ്പത്തി ചരിത്ര കഥ വായിക്കുന്ന വിധത്തിലല്ല സങ്കീർത്തന കവിത വായിക്കേണ്ടത്. ഒരു ഗ്രന്ഥ ശൈലി മനസ്സിലാക്കാതിരിക്കുന്നത് — ഉദ്ദേശ അർത്ഥം തെറ്റ് ഗ്രഹിക്കൽ, ബൈബിൾ വൈരുദ്ധ്യങ്ങൾ കാണൽ — ഇവ ഉണ്ടാക്കും. ഓരോ ശൈലിയും ദൈവ ആശയ വിനിമയം ചെയ്യുന്ന വിധം, യേശു ഈ ശൈലികൾ എങ്ങനെ ഉപയോഗിച്ചു — ഇത് ഈ പഠനം മനസ്സിലാക്കി തരും. ശരിയായ ശൈലി ധാരണ ബൈബിൾ പഠനം ആഴവും കൃത്യതയും ഉള്ളതാക്കുന്നു.',
   'Foundations of Faith'),

  ('bbb00000-e29b-41d4-a716-446655440003', 'hi',
   'पुराने नियम की कहानी',
   'पुराने नियम की बड़ी कहानी सृष्टि से शुरू होती है, पतन से गुज़रती है, और परमेश्वर की एक उद्धार योजना को बढ़ाती रहती है जो अंत में मसीह की ओर इशारा करती है। इब्राहीम के साथ वाचा, मूसा और मुक्ति, दाऊद का राज्य, और भविष्यद्वक्ताओं की पुकार — ये सब एक बड़े नाटक के हिस्से हैं। निर्वासन और वापसी के बीच परमेश्वर की विश्वासयोग्यता देखें — उन्होंने अपनी प्रजा को नहीं छोड़ा। यह समझना कि पुराना नियम कैसे नए नियम से जुड़ता है, यीशु की पहचान को नई गहराई देता है। इस अध्ययन में पुराने नियम को अलग-अलग टुकड़ों में नहीं बल्कि एक सुसंगत, उद्देशपूर्ण कहानी के रूप में देखना सीखें।',
   'Foundations of Faith'),

  ('bbb00000-e29b-41d4-a716-446655440003', 'ml',
   'പഴയ നിയമ കഥ',
   'പഴയ നിയമ കഥ സൃഷ്ടിയിൽ ആരംഭിക്കുന്നു, പതനത്തിലൂടെ കടക്കുന്നു, ഒരു ദൈവ രക്ഷ പദ്ധതി ക്രിസ്തുവിലേക്ക് ചൂണ്ടി വളരുന്നു. അബ്രഹാമുമായുള്ള ഉടമ്പടി, മോശ വഴി മോചനം, ദാവീദ് രാജ്യം, പ്രവാചകരുടെ ദൈവ വിളി — ഇവ ഒരു മഹത്തായ ദൈവ കഥയുടെ ഭാഗങ്ങൾ. പ്രവാസവും തിരിച്ചുവരവും — ദൈവ ജനത്തെ ഉപേക്ഷിക്കാൻ ദൈവം ഒരിക്കലും തയ്യാറല്ലെന്ന ദൈവ വിശ്വസ്തതയുടെ തെളിവ്. പഴയ നിയമം പുതിയ നിയമവുമായി ഏത് വിധം ബന്ധപ്പെടുന്നു — ഈ ധാരണ യേശുവിന്റെ ഐഡൻ്ററ്റിക്ക് ആഴ്‌ചിക്കൽ നൽകുന്നു. ഈ പഠനം പഴയ നിയമം വ്യത്യസ്ത ഭാഗങ്ങൾ ആയി അല്ല, ഒരു ഐക്യ ഉദ്ദേശ കഥ ആയി കാണാൻ സഹായിക്കും.',
   'Foundations of Faith'),

  ('bbb00000-e29b-41d4-a716-446655440004', 'hi',
   'नए नियम की कहानी',
   'नया नियम पुराने नियम की कहानी का एक नाटकीय निरंतरता है — वह सब कुछ जो परमेश्वर ने वादा किया था वह यीशु मसीह में पूरा हुआ। चार सुसमाचार यीशु के जीवन, मृत्यु और पुनरुत्थान को अलग-अलग दृष्टिकोणों से दिखाते हैं। प्रेरितों के काम में देखें पवित्र आत्मा का काम, प्रारंभिक कलीसिया का जन्म और सुसमाचार का संसार में फैलाव। पत्रियाँ समझाती हैं कि यह सुसमाचार रोज़मर्रा के जीवन, रिश्तों और चर्च जीवन में कैसे दिखता है। प्रकाशितवाक्य इस पूरी कहानी का भव्य समापन है — मसीह की जीत, परमेश्वर का राज्य और सब कुछ नया होना।',
   'Foundations of Faith'),

  ('bbb00000-e29b-41d4-a716-446655440004', 'ml',
   'പുതിയ നിയമ കഥ',
   'പുതിയ നിയമം പഴയ നിയമ കഥയുടെ ഒരു ഗംഭീര തുടർച്ച — ദൈവം വാഗ്ദാനം ചെയ്തതൊക്കെ യേശു ക്രിസ്തുവിൽ നിറവേറി. നാല് സുവിശേഷങ്ങൾ യേശുവിന്റെ ജീവിതം, മരണം, പുനരുത്ഥാനം വ്യത്യസ്ത കാഴ്ചപ്പാടുകളിൽ കാണിക്കുന്നു. അപ്പൊ. പ്രവൃത്തിയിൽ പരിശുദ്ധാത്മ ദൗത്യം, ആദ്യ സഭ ജനനം, ലോകത്ത് സുവിശേഷ വ്യാപനം — ഇവ ജീവനുള്ള ചിത്രം. ലേഖനങ്ങൾ ഈ സുവിശേഷം ദൈനംദിന ജീവിതം, ബന്ധം, സഭ ജീവിതം — ഇവയിൽ എങ്ങനെ കാണണം എന്ന് വ്യക്തമാക്കുന്നു. വെളിപ്പാടു ഈ മഹത്തായ കഥയുടെ ഉജ്ജ്വല പൂർത്തി — ക്രിസ്തു ജയം, ദൈവ രാജ്യ ആഗമനം, സകലം നവീകരണം.',
   'Foundations of Faith')

ON CONFLICT (topic_id, language_code) DO NOTHING;

