-- CCC: Baptism and the Lord's Supper (5 topics)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('ccc00000-e29b-41d4-a716-446655440001', 'hi',
   'बपतिस्मा क्या है?',
   'बपतिस्मा एक बाहरी कर्म है जो अंदरूनी वास्तविकता की घोषणा करता है — मसीह की मृत्यु, दफन और पुनरुत्थान के साथ विश्वासी की पहचान। रोमियों 6 में पौलुस बताते हैं कि बपतिस्मा पुराने जीवन की मृत्यु और नए जीवन की शुरुआत का चिह्न है। यह उद्धार नहीं देता, लेकिन उद्धार की घोषणा करता है — जैसे अंगूठी विवाह का प्रतीक है पर विवाह नहीं। यह समझना ज़रूरी है कि बपतिस्मा कौन ले सकता है, इसका सही तरीका क्या है, और यह कलीसिया के साथ जुड़ने का एक सार्वजनिक कदम क्यों है। इस अध्ययन में बपतिस्मे का पूरा बाइबलीय अर्थ, उसका इतिहास और उसकी व्यावहारिक महत्ता समझें।',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440001', 'ml',
   'സ്നാനം എന്നാൽ എന്ത്?',
   'സ്നാനം ഒരു ബാഹ്യ കർമ്മം — ഉള്ളിലെ ഒരു യഥാർത്ഥ്യം പ്രഖ്യാപിക്കുന്ന ദൃശ്യ ചടങ്ങ്, ക്രിസ്തുവിന്റെ മരണ-ദഫൻ-പുനരുത്ഥാനവുമായി വിശ്വാസിയുടെ ഐക്യം. റോമർ 6-ൽ പൗലൊസ് വിശദീകരിക്കുന്നു: സ്നാനം പഴയ ജീവിതത്തിന്റെ മരണവും പുതിയ ജീവിതത്തിന്റെ ആരംഭവും ചിത്രീകരിക്കുന്ന ഒരു അടയാളം. ഇത് രക്ഷ നൽകുന്നില്ല, രക്ഷ പ്രഖ്യാപിക്കുന്നു — ഒരു മോതിരം വിവാഹ ചിഹ്നം ആണ്, വിവാഹം അല്ല, ഇതുപോലെ. ആർ സ്നാനം ഏൽക്കണം, ശരിയായ രീതി, ഇത് സഭ ജീവിതവുമായുള്ള ബന്ധം — ഇത് മനസ്സിലാക്കൽ ആവശ്യം. ഈ പഠനം സ്നാനത്തിന്റെ ബൈബിൾ അർത്ഥം, ചരിത്രം, പ്രായോഗിക പ്രധാന്യം — ഇവ ആഴ്‌ചിക്കൽ ഉൾക്കൊള്ളും.',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440002', 'hi',
   'बपतिस्मा क्यों लें?',
   'यीशु ने अपने शिष्यों को स्पष्ट आज्ञा दी — जाओ, शिष्य बनाओ, बपतिस्मा दो (मत्ती 28:19)। बपतिस्मा मसीह के प्रति आज्ञाकारिता का पहला सार्वजनिक कदम है, जो कहता है: "मैं यीशु का हूँ।" यह न केवल विश्वासी की पहचान बदलता है, बल्कि उसे एक समुदाय में जोड़ता है — वह अकेला मसीही नहीं है। पतरस ने पेन्तेकुस्त पर पश्चाताप करने वालों से कहा: "बपतिस्मा लो" (प्रे.काम 2:38)। यह अध्ययन उन लोगों के लिए है जो सोच रहे हैं — क्या मुझे बपतिस्मा लेना चाहिए? और वे लोग जो यह समझना चाहते हैं कि इस आज्ञा का पालन उनकी विश्वास यात्रा में क्या अर्थ रखता है।',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440002', 'ml',
   'സ്നാനം ഏൽക്കേണ്ടത് എന്തിന്?',
   'യേശു തന്റെ ശിഷ്യന്മാർക്ക് വ്യക്തമായ കൽപ്പന നൽകി — പോകുക, ശിഷ്യരെ ഉണ്ടാക്കുക, സ്നാനം കൊടുക്കുക (മത്തായി 28:19). സ്നാനം ക്രിസ്തുവിനോടുള്ള അനുസരണത്തിന്റെ ആദ്യ പരസ്യ ചുവട് — "ഞാൻ യേശുവിന്റേതാണ്" എന്ന പ്രഖ്യാപനം. ഇത് വിശ്വാസിയുടെ ഐഡൻ്ററ്റി മാറ്റുക മാത്രമല്ല, ഒരു ജനതയുടെ ഭാഗം ആക്കുകയും ചെയ്യുന്നു. പെന്തക്കൊസ്ത് ദിനം അനുതപിച്ചവരോട് പത്രൊസ് പറഞ്ഞു: "സ്നാനം ഏൽക്കുക" (അപ്പൊ. 2:38). "ഞാൻ സ്നാനം ഏൽക്കണോ?" — ഇത് ആലോചിക്കുന്നവർക്കും ഈ കൽപ്പനയുടെ ആഴ അർത്ഥം മനസ്സിലാക്കാൻ ആഗ്രഹിക്കുന്നവർക്കും ഈ പഠനം ഉതകും.',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440003', 'hi',
   'प्रभु भोज: स्मरण और घोषणा',
   'यीशु ने अपनी मृत्यु की रात खुद इस भोज को स्थापित किया — रोटी और दाखरस मसीह के टूटे शरीर और बहाए लहू के प्रतीक हैं। 1 कुरिन्थियों 11 में पौलुस बताते हैं कि यह एक स्मरण ("मुझे याद करते हुए"), एक घोषणा ("प्रभु की मृत्यु दर्शाते हो") और एक आशा ("जब तक वह आए") है। यह बार-बार यीशु के बलिदान पर हमारा ध्यान केंद्रित करता है और हमें याद दिलाता है कि हमारा उद्धार उसकी लहू से है। यह एक व्यक्तिगत नहीं बल्कि सामुदायिक कार्य है — हम एक देह के रूप में एक साथ मेज़ पर आते हैं। इस अध्ययन में इस भोज की स्थापना, अर्थ, आवृत्ति और आध्यात्मिक महत्ता को गहराई से समझें।',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440003', 'ml',
   'കർത്തൃ അത്താഴം: ഓർക്കലും പ്രഘോഷണവും',
   'തന്റെ മരണ രാത്രി യേശു ഈ ഭക്ഷണം സ്ഥാപിച്ചു — അപ്പം ക്രിസ്തുവിന്റെ ശരീരം, വീഞ്ഞ് ക്രിസ്തുവിന്റെ രക്തം ആണ് ദൃശ്യ ചിഹ്നം. 1 കൊരിന്ത്യർ 11-ൽ പൗലൊസ് വ്യക്തമാക്കുന്നു: ഇത് ഒരു ഓർമ്മ ("എന്നെ ഓർക്കുക"), ഒരു പ്രഘോഷണ ("കർത്താവിന്റെ മരണം ഘോഷിക്കുക"), ഒരു പ്രത്യാശ ("അവൻ വരും വരെ") — ഒരേ ഭക്ഷണത്തിൽ ഈ മൂന്ന് ആഴ അർത്ഥം. ഇത് ആവർത്തിക്കുന്നത് ക്രിസ്തു യാഗത്തിൽ ദൃഷ്ടി ഉറ്റ് രക്ഷ ആ രക്തത്തിൽ ആണ് എന്ന ഓർമ്മ നൽകുന്നു. ഇത് വ്യക്തിഗതം അല്ല, ഒരു ദേഹം ആയി ഒരുമിച്ച് മേശ അടുക്കൽ. ഈ ഭക്ഷണ സ്ഥാപനം, അർത്ഥം, ആവൃത്തി, ആത്മ ഗൗരവം — ഇവ ഈ പഠനം ആഴ്‌ചിക്കൽ ഉൾക്കൊള്ളും.',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440004', 'hi',
   'योग्य रीति से भाग लेना',
   '1 कुरिन्थियों 11:27-29 में पौलुस गंभीर चेतावनी देते हैं: जो कोई अयोग्य रीति से प्रभु की रोटी खाए और कटोरे से पीए वह प्रभु के शरीर और लहू का अपराधी होगा। लेकिन इसका मतलब यह नहीं कि सिद्ध लोग ही आ सकते हैं — बल्कि हमें "अपने आप को परखना" है (आत्मपरीक्षा)। इस परखने में शामिल है: क्या मैं पश्चाताप में हूँ? क्या मैं सहविश्वासियों के साथ मेल में हूँ? क्या मेरे दिल में भ्रष्टाचार या कटुता है? यह प्रभु भोज को डर की जगह नहीं बल्कि नम्रता और कृतज्ञता का समय बनाता है। इस अध्ययन में सीखें कि हृदय की सही तैयारी के साथ मेज़ पर कैसे आएं।',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440004', 'ml',
   'യോഗ്യമായ രീതിയിൽ പങ്കെടുക്കൽ',
   '1 കൊരിന്ത്യർ 11:27-29-ൽ പൗലൊസ് ഗൗരവമായ മുന്നറിയിപ്പ് നൽകുന്നു: അയോഗ്യ രീതിയിൽ ഭക്ഷിക്കുന്നവൻ കർത്താവിന്റെ ശരീര-രക്ത കുറ്റക്കാരൻ. എന്നാൽ ഇതിന്റെ അർത്ഥം തികഞ്ഞവർ മാത്രം ഭക്ഷിക്കണം എന്നല്ല — "സ്വയം പരിശോധിക്കണം" (ആത്മ പരിശോധന) എന്നതാണ്. ഈ പരിശോധനയിൽ ഉൾപ്പെടുന്നത്: ഞാൻ അനുതാപത്തിൽ ഉണ്ടോ? സഹ വിശ്വാസികളുമായി ഐക്യത്തിൽ ഉണ്ടോ? ഹൃദയത്തിൽ വൈരം അല്ലെങ്കിൽ ദ്വേഷം ഉണ്ടോ? ഇത് കർത്തൃ അത്താഴം ഭയത്തിന്റെ ഇടം ആക്കുകയല്ല, താഴ്മ, കൃതജ്ഞത, ഹൃദ ശ്രദ്ധ — ഇവ ഉൾക്കൊള്ളുന്ന ഒരു ദൈവ ക്ഷണ ആക്കുകയാണ്. ഈ പഠനം ഹൃദ ശ്രദ്ധോടെ മേശ അടുക്കൽ വിധം പഠിപ്പിക്കും.',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440005', 'hi',
   'बपतिस्मा, प्रभु भोज और कलीसिया की सदस्यता',
   'बपतिस्मा और प्रभु भोज — ये दोनों प्रभु-नियुक्त विधियाँ व्यक्तिगत धर्म कर्म नहीं हैं, बल्कि सामुदायिक प्रथाएँ हैं जो कलीसिया के जीवन से अविभाज्य हैं। बपतिस्मा कलीसिया में प्रवेश का द्वार है, और प्रभु भोज उस जीवन को बार-बार नवीनीकरण करता है। कलीसिया की सदस्यता बाइबलीय नहीं तो ये दोनों कार्य अर्थहीन हो जाते हैं — एक परिवार से बाहर रहकर परिवार का भोज खाने जैसा। यह अध्ययन यह भी संबोधित करता है: क्या मुझे औपचारिक रूप से कलीसिया का सदस्य बनना चाहिए? सदस्यता का उद्देश्य क्या है? जवाबदेही, प्रेम, सेवा और आत्मिक विकास — ये सब मिलकर बाइबलीय कलीसिया जीवन बनाते हैं।',
   'Church & Community'),

  ('ccc00000-e29b-41d4-a716-446655440005', 'ml',
   'സ്നാനം, കർത്തൃ അത്താഴം, സഭാ അംഗത്വം',
   'സ്നാനവും കർത്തൃ അത്താഴവും — ഈ രണ്ട് ആചാരങ്ങളും ("ദൈവ കർമ്മങ്ങൾ") വ്യക്തിഗത ഭക്തി ചടങ്ങുകൾ അല്ല, സഭ ജീവിതവുമായി അവിഭാജ്യ ബന്ധം ഉള്ള സഭ ആചരണങ്ങൾ. സ്നാനം സഭ ജീവിതത്തിലേക്കുള്ള കവാടം, കർത്തൃ അത്താഴം ആ ജീവിതം ആവർത്തിച്ച് നവീകരിക്കുന്ന ഭക്ഷണം. ഒരു കുടുംബ ഭക്ഷണം ആ കുടുംബ ഭാഗം അല്ലാത്തവർക്ക് അർത്ഥ ഹീനം — ഇതുപോലെ ഈ ആചാരങ്ങൾ സഭ അംഗത്വം ഇല്ലാതെ അർത്ഥ ഹീനം. ഒൗദ്യോഗിക സഭ അംഗത്വം ആവശ്യം ഉണ്ടോ? ഉദ്ദേശം എന്ത്? — ഉത്തരവാദ ബന്ധം, സ്നേഹം, സേവനം, ആത്മ വളർച്ച — ഈ ഘടകങ്ങൾ ഈ പഠനം ആഴ്‌ചിക്കൽ ആക്കും.',
   'Church & Community')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- DDD: Who Is the Holy Spirit? (4 topics)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('ddd00000-e29b-41d4-a716-446655440001', 'hi',
   'पुराने नियम में पवित्र आत्मा',
   'पवित्र आत्मा नए नियम की शुरुआत नहीं है — वह सृष्टि के पहले दिन से जल के ऊपर मंडराता था (उत्पत्ति 1:2)। पुराने नियम में आत्मा ने भविष्यद्वक्ताओं को प्रेरित किया, न्यायियों और राजाओं को सामर्थ दी, और कारीगरों को कलाकारी के लिए भर दिया। लेकिन पुराने नियम में आत्मा का निवास चुनिंदा लोगों में था और अस्थायी भी था — मूसा की इच्छा थी कि सब लोगों में आत्मा हो (गिनती 11:29)। योएल की भविष्यवाणी थी कि एक दिन परमेश्वर अपना आत्मा सब पर उँडेलेगा — जो पेन्तेकुस्त पर पूरी हुई। इस अध्ययन में देखें कैसे पवित्र आत्मा का काम पुराने नियम से नए नियम तक कैसे विकसित हुआ और क्यों यह त्रिएकता की समझ के लिए महत्वपूर्ण है।',
   'Foundations of Faith'),

  ('ddd00000-e29b-41d4-a716-446655440001', 'ml',
   'പഴയ നിയമത്തിൽ പരിശുദ്ധാത്മാവ്',
   'പരിശുദ്ധാത്മാവ് പുതിയ നിയമ ആരംഭം അല്ല — ഉൽപ്പ. 1:2 ൽ സൃഷ്ടി ദിനം മുതൽ ജലോ പരിശുദ്ധാത്മ ചലനം. പഴയ നിയമത്തിൽ ആത്മ പ്രവചന നിശ്വാസം, ന്യായാധിപ-രാജ ശക്തി ദാനം, കലകളുടെ ദൈവ ദാനം — ഇവ ഉൾക്കൊള്ളുന്ന ഒരു ആത്മ ദൗത്യം. പഴയ നിയമ ആത്മ ആവേശം ചുരുക്കം ആളുകളിൽ, ചിലപ്പോൾ താൽക്കാലികം — മോശ ആഗ്രഹിച്ചു "ദൈവ ജനം ഒക്കെ ആത്മ ആവേശ ഭരിതർ ആകണം" (സംഖ്യ 11:29). യോവേൽ ഒരു ദിനം ദൈവം ആത്മ ഒക്കെ ഒഴുക്കും എന്ന് പ്രവചിച്ചു — പെന്തക്കൊസ്ത് ദിനം നിറവേറി. ഈ ആത്മ ദൗത്യം പഴയ-പുതിയ നിയമ ഉടനീളം എങ്ങനെ വളർന്നു, ത്രിത്വ ദൈവ ധാരണക്ക് ഇതിന്റെ പ്രധാന്യം — ഈ പഠനം ഇവ കണ്ടെത്തുക.',
   'Foundations of Faith'),

  ('ddd00000-e29b-41d4-a716-446655440002', 'hi',
   'पवित्र आत्मा और उद्धार',
   'मसीही विश्वास का एक बुनियादी सत्य यह है कि पवित्र आत्मा के काम के बिना कोई भी मसीह के पास नहीं आ सकता — यीशु ने यूहन्ना 3 में निकुदेमुस से कहा "जब तक कोई पानी और आत्मा से जन्म न ले वह परमेश्वर के राज्य में प्रवेश नहीं कर सकता।" पवित्र आत्मा पाप का बोध कराता है, हृदय को नरम करता है, मसीह की सुंदरता दिखाता है और हमें विश्वास करने की इच्छा देता है। नया जन्म (पुनर्जनन) उसी का काम है — हम खुद से नहीं बदलते, आत्मा हमें बदलता है। उद्धार के बाद भी आत्मा हमारे अंदर रहता है, हमें परमेश्वर के पुत्र होने की गवाही देता है और हमें मसीह जैसा बनाने की प्रक्रिया में काम करता है। यह अध्ययन उद्धार में आत्मा की पूरी भूमिका को स्पष्ट करता है।',
   'Foundations of Faith'),

  ('ddd00000-e29b-41d4-a716-446655440002', 'ml',
   'പരിശുദ്ധാത്മാവും രക്ഷയും',
   'ക്രൈസ്തവ വിശ്വാസ ഒരു അടിസ്ഥാന സത്യം: പരിശുദ്ധാത്മ ദൗത്യം ഇല്ലാതെ ആരും ക്രിസ്തുവിനെ സ്വീകരിക്കുകയില്ല — യോഹ 3-ൽ നിക്കൊദേമൊസിനോട് യേശു: "ജലം ആത്മ ജനനം ഇല്ലാതെ ദൈവ രാജ്യ പ്രവേശം ഇല്ല." ആത്മ പ്രവൃത്തി: പാപ ബോദ്ധ്യം, ഹൃദ കോമളം, ക്രിസ്തു സൗന്ദര്യ ദർശനം, വിശ്വസിക്കാൻ ഇഛ ദാനം. നവ ജനനം (Regeneration) ആത്മ ദൗത്യം — നാം സ്വയം മാറുകയല്ല, ആത്മ ദൈവം മാറ്റുന്നു. രക്ഷക്ക് ശേഷവും ആത്മ ഉൾ ആവാസം, ദൈവ പുത്ര ഐഡൻ്ററ്റി ഉറ്റ് ദൈവ ദൃഢ, ക്രിസ്തൂ ദൃഷ്ടി പ്രക്രിയ. ഈ പഠനം രക്ഷ ഉടനീളം ആത്മ ദൗത്യം ആഴ്‌ചിക്കൽ വ്യക്തമാക്കും.',
   'Foundations of Faith'),

  ('ddd00000-e29b-41d4-a716-446655440003', 'hi',
   'आत्मा का फल',
   'गलातियों 5:22-23 में नौ गुणों की सूची है जो पवित्र आत्मा एक विश्वासी के जीवन में उत्पन्न करता है: प्रेम, आनंद, शांति, धैर्य, कोमलता, भलाई, विश्वासयोग्यता, नम्रता और आत्म-संयम। पौलुस इन्हें "फल" कहते हैं — जैसे फल पेड़ की प्रकृति का स्वाभाविक परिणाम है, वैसे ये गुण आत्मा की प्रकृति का स्वाभाविक परिणाम हैं। ये नियमों का पालन करके नहीं, बल्कि आत्मा के अनुसार चलने से उत्पन्न होते हैं। इस अध्ययन में प्रत्येक गुण की व्यावहारिक परिभाषा, यह कैसे दिखता है, और आत्मा के विरुद्ध शरीर के कार्यों से यह कैसे अलग है — यह समझें। यह ज्ञान आत्म-परिवर्तन के लिए संघर्ष करने वाले हर विश्वासी के लिए महत्वपूर्ण है।',
   'Christian Living'),

  ('ddd00000-e29b-41d4-a716-446655440003', 'ml',
   'ആത്മാവിന്റെ ഫലം',
   'ഗലാത്യർ 5:22-23 ൽ ഒൻപത് ഗുണ ഫലങ്ങൾ: സ്നേഹം, സന്തോഷം, സമാധാനം, ദീർഘ ക്ഷമ, ദയ, നന്മ, വിശ്വസ്തത, സൗമ്യത, ആത്മ നിയന്ത്രണം. പൗലൊസ് ഇവ "ഫലം" എന്ന് വിളിക്കുന്നു — ഒരു മരത്തിന്റെ ഫലം അതിന്റെ ഉൾ സ്വഭാവ ഫലം, ഇതു പോലെ ഈ ഗുണങ്ങൾ ആത്മ ദൈവ ഉൾ ദൗത്യ ഫലം. ഇവ നിയമ പ്രകാരം ഉൽപ്പാദിക്കാൻ ആകില്ല — ആത്മ ദൈവ കൂടെ ചലിക്കൽ ഇവ ഉൽപ്പാദിക്കുന്നു. ഓരോ ഗുണ ഫലത്തിന്റെ പ്രായോഗിക നിർവ്വചനം, ദൈനംദിന ജീവിത ദൃശ്യ രൂപം, ശരീര ദൗത്യ നിന്ന് ഇവ എങ്ങനെ വ്യത്യസ്തം — ഈ പഠനം ഇവ ആഴ്‌ചിക്കൽ ഉൾക്കൊള്ളും. ആത്മ മാറ്റത്തിനായി ഗുസ്തി ചെയ്യുന്ന ഓരോ വിശ്വാസിക്കും ഇത് ആവശ്യ ജ്ഞാനം.',
   'Christian Living'),

  ('ddd00000-e29b-41d4-a716-446655440004', 'hi',
   'आत्मा से भरे रहना',
   'एफिसियों 5:18 में पौलुस एक आज्ञा देते हैं: "मदिरा से मतवाले मत बनो... परंतु आत्मा से परिपूर्ण होते रहो।" यह एक बार की घटना नहीं, बल्कि एक निरंतर प्रक्रिया है — यूनानी भाषा में "भरते रहो" है। मदिरा जैसे एक बाहरी पदार्थ से नियंत्रित होने के बजाय, हम एक आंतरिक शक्ति — पवित्र आत्मा — से नियंत्रित हों। इसके व्यावहारिक साधन हैं: पश्चाताप में जीना, परमेश्वर के वचन को बहुतायत से रखना, प्रार्थना में लगे रहना, और एक दूसरे के साथ भजन कीर्तन में शामिल रहना। यह अध्ययन बताएगा कि आत्मा के साथ हमारे जीवन में ऐसी कौन-सी बाधाएँ हैं जिन्हें पहचानना और दूर करना ज़रूरी है।',
   'Spiritual Disciplines'),

  ('ddd00000-e29b-41d4-a716-446655440004', 'ml',
   'ആത്മ നിറഞ്ഞ ജീവിതം',
   'എഫേസ്യർ 5:18 ൽ ഒരു കൽപ്പന: "മദ്യ ആസക്തനല്ല... ആത്മ നിറഞ്ഞവൻ ആയിരിക്കുക." ഇത് ഒരു തവണ ദൈവ അനുഭവം അല്ല — ഗ്രീക്കിൽ "നിറഞ്ഞ് കൊണ്ടിരിക്കുക" ആണ്. ഒരു ബാഹ്യ വസ്തു ദ്രവ്യം നിയന്ത്രിക്കുന്നതിനു പകരം, ഒരു ഉൾ ശക്തി — പരിശുദ്ധാത്മ ദൈവം — നിയന്ത്രിക്കട്ടെ. ഇതിന്റെ പ്രായോഗിക ഉപകരണങ്ങൾ: അനുതാപ ജീവിതം, ദൈവ വചന ബഹുലം, പ്രാർത്ഥന ജീവിതം, ഗാനം-കൃതജ്ഞ ആരാധന. ആത്മ ദൗത്യം തടഞ്ഞ് നിർത്തുന്ന ഹൃദ ഘടകങ്ങൾ തിരിച്ചറിഞ്ഞ് ഒഴിവാക്കൽ — ഈ പഠനം ഇത് ആഴ്‌ചിക്കൽ ഉൾക്കൊള്ളും.',
   'Spiritual Disciplines')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- EEE: Theology of Suffering (4 topics)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('eee00000-e29b-41d4-a716-446655440001', 'hi',
   'भजनों में दुख: विलाप करना सीखना',
   'भजनों का एक तिहाई से अधिक भाग विलाप है — यानी परमेश्वर दर्द में रोने की, सवाल पूछने की और ईमानदारी से बात करने की अनुमति देता है। विलाप के भजनों में एक सामान्य रूप दिखता है: परमेश्वर से शिकायत, उनकी विश्वासयोग्यता को याद करना, विश्वास की पुनर्घोषणा। यह झूठे धैर्य या खुशहाली के नाटक का विरोध है — परमेश्वर सब कुछ ठीक है कहने की माँग नहीं करता। भजन 22 (जो यीशु ने क्रूस पर उद्धृत किया) दिखाता है कि ईमानदार पीड़ा और गहरा विश्वास एक साथ रह सकते हैं। इस अध्ययन में सीखें कि विलाप की भाषा कैसे अपनाएं और दर्द में परमेश्वर के साथ ईमानदार बातचीत कैसे करें।',
   'Christian Living'),

  ('eee00000-e29b-41d4-a716-446655440001', 'ml',
   'സങ്കീർത്തനങ്ങളിൽ ദുഃഖം: വിലാപം പഠിക്കൽ',
   'സങ്കീർത്തനങ്ങളിൽ ഒരു തൃതീയ ഭാഗം വിലാപ സങ്കീർത്തനങ്ങൾ — ദൈവ ജനത്തിന് ദൈവ മുൻപിൽ കരയൽ, ചോദ്യം ചോദിക്കൽ, ഹൃദ ബോധ്യ ആഖ്യാനം അനുവദനീയം. വിലാപ ഗ്രന്ഥ പൊതു ഘടന: ദൈവ ആഹ്വാനം, ദുഃഖ ആഖ്യാനം, ദൈവ വിശ്വസ്തത ഓർക്കൽ, വിശ്വാസ പുനർ പ്രഖ്യാപനം. ഇത് കൃത്രിമ ക്ഷമ അല്ലെങ്കിൽ "എല്ലാം ഒക്കെ" ഭക്തി ചിത്രത്തിന്റെ എതിർ — ദൈവം "ഞാൻ ഒക്കെ" പറ്റും എന്ന് ആവശ്യ ഇല്ല. സങ്കീർ 22 (ക്രൂശിൽ യേശു ഉദ്ധരിച്ചത്) കാണിക്കുന്നു: ഹൃദ ബോദ്ധ്യ വേദനയും ആഴ വിശ്വാസവും ഒരുമിച്ച് നിൽക്കാം. ഈ പഠനം വിലാപ ഭാഷ ഉൾക്കൊള്ളൽ, ദുഃഖ സമയ ദൈവ ഹൃദ ആശ്രയ ഭാഷ — ഇവ ഉൾക്കൊള്ളും.',
   'Christian Living'),

  ('eee00000-e29b-41d4-a716-446655440002', 'hi',
   'अय्यूब और दुख का रहस्य',
   'अय्यूब की कहानी दुख के सबसे कठिन सवाल को सामने रखती है: यदि परमेश्वर अच्छे हैं, तो धर्मी लोग क्यों कष्ट सहते हैं? अय्यूब धर्मी था — और फिर भी उसने सब कुछ खो दिया। उसके तीन मित्रों ने सरल जवाब दिए: "तुमने पाप किया होगा" — लेकिन परमेश्वर ने उन्हें गलत ठहराया। अय्यूब ने परमेश्वर से लड़ाई की, सवाल किए, और अंत में परमेश्वर ने उसे तूफान से जवाब दिया — न समझाने के साथ बल्कि अपनी महिमा दिखाकर। यह रहस्य यह है: हमें सभी "क्यों" के जवाब नहीं मिलते, लेकिन हम उस परमेश्वर पर भरोसा कर सकते हैं जो तूफान में भी हमारे साथ है।',
   'Christian Living'),

  ('eee00000-e29b-41d4-a716-446655440002', 'ml',
   'ഇയ്യോബും ദുഃഖ രഹസ്യവും',
   'ഇയ്യോബ് ദുഃഖത്തിന്റെ ഏറ്റവും കഠിന ചോദ്യം ഉന്നയിക്കുന്നു: ദൈവം നല്ലവനാണെങ്കിൽ, നീതിമാൻ കഷ്ടം അനുഭവിക്കുന്നത് എന്തിന്? ഇയ്യോബ് നീതിമാൻ ആയിരുന്നു — എന്നിട്ടും സർവ്വ നഷ്ടം. അദ്ദേഹ സ്നേഹിതന്മാർ ലളിത ഉത്തരം: "നീ പാപം ചെയ്തിരിക്കും" — ദൈവം ഇവരെ തെറ്റ് ആക്കി. ഇയ്യോബ് ദൈവ ന്നോട് ഗുസ്തി ചെയ്തു, ചോദ്യം ചോദിച്ചു — ഒടുവിൽ ദൈവം കൊടുങ്കാറ്റിൽ ഉത്തരം നൽകി: വിശദീകരണം അല്ല, ദൈവ മഹത്ത്വ ദർശനം. ഈ രഹസ്യം: "എന്തുകൊണ്ട്" ഉത്തരം ലഭിക്കില്ല, പക്ഷേ കൊടുങ്കാറ്റിലും കൂടെ ഉള്ള ദൈവ ദൃഢ ആശ്രയം ലഭിക്കും.',
   'Christian Living'),

  ('eee00000-e29b-41d4-a716-446655440003', 'hi',
   'क्रूस और हमारा दुख',
   'क्रूस केवल पाप के लिए परमेश्वर का समाधान नहीं है — यह दुख के लिए भी उनका जवाब है। यीशु परमेश्वर का पुत्र होकर भी दर्द, अस्वीकृति, विश्वासघात और मृत्यु से गुज़रा — वह हमारी पीड़ा को दूर से नहीं देखता, वह उसमें उतरा। इब्रानियों 4:15 कहता है कि हमारा महायाजक हमारी कमज़ोरियों में हमारे साथ सहानुभूति कर सकता है। क्रूस यह भी दिखाता है कि परमेश्वर दुख को बर्बाद नहीं होने देते — यीशु की पीड़ा ने सबसे बड़ी भलाई को जन्म दिया। इस अध्ययन में जानें कि क्रूस हमारी पीड़ा को कैसे अर्थ, उद्देश्य और अंतिम आशा देता है।',
   'Foundations of Faith'),

  ('eee00000-e29b-41d4-a716-446655440003', 'ml',
   'കുരിശും നമ്മുടെ ദുഃഖവും',
   'കുരിശ് പാപ പ്രശ്ന ദൈവ ഉത്തരം മാത്രമല്ല — ദുഃഖ പ്രശ്ന ദൈവ ഉത്തരവും ആണ്. ദൈവ പുത്രൻ ആയ യേശു വേദന, തിരസ്കാരം, വഞ്ചന, മരണം — ഇവ അനുഭവിച്ചു — അവൻ നമ്മുടെ പീഡ ദൂരത്ത് നിന്ന് കണ്ടതല്ല, ഇറങ്ങി ഉള്ളിൽ ഇടപഴകി. എബ്രായർ 4:15 — നമ്മുടെ ദൌർബ്ബല്യ ക്ഷണം ആ ഒക്കെ അനുഭവിച്ച് ബോദ്ധ്യം നേടിയ ഒരു മഹാ പുരോഹിതൻ. കുരിശ് കാണിക്കുന്നു: ദൈവം ദുഃഖം പാഴ് ആക്കില്ല — ക്രിസ്തു ക്ലേശം ഏറ്റവും വലിയ ഭലം ഉൽപ്പാദിപ്പിച്ചു. ഈ പഠനം ക്രൂശ് നമ്മുടെ വേദനക്ക് അർത്ഥം, ഉദ്ദേശ്യം, ആത്യന്തിക പ്രത്യാശ — ഇവ നൽകുന്ന വിധം കണ്ടെത്തും.',
   'Foundations of Faith'),

  ('eee00000-e29b-41d4-a716-446655440004', 'hi',
   'दुख में आशा: शाश्वत नज़रिया',
   'रोमियों 8:18 पौलुस का एक साहसी दावा है: "मैं समझता हूँ कि इस वर्तमान समय के दुख उस महिमा के सामने कुछ भी नहीं जो हम में प्रकट होगी।" यह दर्द को कम करना नहीं है — पौलुस खुद ने कोड़े, जेल, जहाज़तूफान और मृत्यु का भय सहा। शाश्वत नज़रिया दर्द की तीव्रता नहीं बदलता, लेकिन उसके अर्थ और दिशा को बदलता है। 2 कुरिन्थियों 4 में पौलुस कहते हैं: हमारा "हल्का और क्षणिक दुख" हमारे लिए अनंत और असीम महिमा तैयार करता है। यह अध्ययन सिखाएगा कि अनंत जीवन की वास्तविकता आज की पीड़ा में कैसे व्यावहारिक शक्ति देती है।',
   'Christian Living'),

  ('eee00000-e29b-41d4-a716-446655440004', 'ml',
   'ദുഃഖത്തിൽ പ്രത്യാശ: ശാശ്വത ദർശനം',
   'റോമർ 8:18 ൽ പൗലൊസ് ഒരു ധൈര്യ അവകാശ വാദം: "ഇപ്പോഴത്തെ കഷ്ടം നമ്മിൽ വെളിപ്പെടാനുള്ള മഹത്ത്വത്തിനു നിരക്കുന്നതല്ല." ഇത് ദുഃഖം നിരസിക്കലല്ല — പൗലൊസ് ചാട്ടവാർ, കാരാഗൃഹം, കടൽ ദുരന്തം, മരണ ഭയം — ഇവ ഒക്കെ സഹിച്ചു. ശാശ്വത ദർശനം ദുഃഖ തീവ്രത മാറ്റുകയല്ല — ദുഃഖ അർത്ഥവും ദിശയും മാറ്റുന്നു. 2 കൊരിന്ത്യർ 4 — നമ്മുടെ "ലഘു, ക്ഷണ ക്ലേശം" ശാശ്വത, ഭാര മഹത്ത്വം ഉൽപ്പാദിപ്പിക്കുന്നു. ഈ ശാശ്വത ജീവ യഥാർത്ഥ്യം ഇന്നത്തെ ദുഃഖ നടുവിൽ പ്രായോഗിക ശക്തി ദാനം ചെയ്യുന്ന വിധം ഈ പഠനം ഉൾക്കൊള്ളും.',
   'Christian Living')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- FFF: Money, Generosity, and the Gospel (6 topics)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('fff00000-e29b-41d4-a716-446655440001', 'hi',
   'बाइबल पैसे के बारे में क्या कहती है?',
   'यीशु ने परमेश्वर के राज्य से भी अधिक बार धन के बारे में बात की — उसके लगभग एक तिहाई दृष्टान्त पैसे और संपत्ति से संबंधित हैं। बाइबल पैसे को बुरा नहीं कहती, बल्कि पैसे के प्रति हमारे दिल की स्थिति को प्रकट करती है — "धन का लोभ सब बुराइयों की जड़ है" (1 तीम. 6:10)। नीतिवचन में धन के बारे में व्यावहारिक ज्ञान है, यीशु के वचनों में चेतावनी और मुक्ति है, और पौलुस के पत्रों में संतोष की शांति है। यह अध्ययन बाइबल की पूरी शिक्षा को एक साथ देखता है — न केवल दशांश, बल्कि पैसे के साथ हमारे पूरे संबंध को। यह विषय हर किसी के लिए व्यावहारिक है क्योंकि हम सब हर दिन धन से जुड़े निर्णय लेते हैं।',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440001', 'ml',
   'ബൈബിൾ പണത്തെക്കുറിച്ച് എന്ത് പറയുന്നു?',
   'ദൈവ രാജ്യത്തേക്കാൾ അടിക്കടി യേശു ധനം, ഉടമ ഉദ്ദേശ്യം — ഈ വിഷയ സംസാരിച്ചു — ഏകദേശം ഒരു തൃതീയ ഉപമ ഇതിനെക്കുറിച്ചാണ്. ബൈബിൾ പണം ദുഷ്ടം എന്ന് പറയുന്നില്ല — "ഐശ്വര്യ ആഗ്രഹം സകല ദോഷ വേര്" (1 തിമൊ. 6:10). സദൃ. ൽ ധന ബോദ്ധ്യ ജ്ഞാനം, യേശു വചനം ൽ മുന്നറിയിപ്പ്-മോചനം, പൗലൊ ലേഖനം ൽ തൃപ്തി സമാധാനം. ഈ പഠനം ബൈബിൾ ധന ഉപദേശം ഒക്കെ ഒരുമിച്ച് കാണുന്നു — ദശാംശം മാത്രം അല്ല, ധനവുമായുള്ള നമ്മുടെ ഹൃദ ബന്ധം ഒക്കെ. ഈ വിഷയം ഓരോ ദിനം ധന തീരുമാനം ചെയ്യുന്ന ഓരോ ജനത്തിനും ഉദ്ദേശ്യ ഉൾക്കൊള്ളും.',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440002', 'hi',
   'संतोष बनाम लालच',
   '1 तीमुथियुस 6:6 में एक क्रांतिकारी कथन है: "धर्मपरायणता के साथ संतोष बड़ी कमाई है।" आधुनिक संस्कृति हमेशा अधिक की माँग करती है — अधिक पैसा, बड़ा घर, नई गाड़ी। लालच यह विश्वास है कि खुशी अगली चीज़ में है। बाइबलीय संतोष निष्क्रियता नहीं है — यह परमेश्वर की व्यवस्था में एक सक्रिय विश्वास है कि वह पर्याप्त देते हैं। पौलुस ने कहा उसने संतोषी होना सीखा — यह स्वभाव से नहीं आता, आत्मा से सीखना पड़ता है। यह अध्ययन लालच की जड़ों, संतोष की सुंदरता और परमेश्वर में संतुष्टि पाने के व्यावहारिक तरीकों को संबोधित करता है।',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440002', 'ml',
   'തൃപ്തി vs. അത്യാഗ്രഹം',
   '1 തിമൊ. 6:6 ൽ ഒരു വിപ്ലവ ഘോഷണ: "ദൈവ ഭക്തിക്കോടൊപ്പം തൃപ്തി ഉണ്ടായിരിക്കൽ വലിയ ലാഭം." ആധുനിക സംസ്കാരം ഒക്കെ "കൂടുതൽ" ആവശ്യ ഉണ്ടാക്കുന്നു — കൂടുതൽ പണം, വലിയ വീട്, പുതിയ വാഹനം. അത്യാഗ്രഹം ഈ വിശ്വാസം: "അടുത്ത ഒരു കൂടി ലഭിച്ചാൽ സന്തോഷം." ബൈബിൾ തൃപ്തി നിഷ്ക്രിയ ജീവിതം അല്ല — ദൈവ കരുതൽ വിശ്വസിക്കൽ ഒരു സക്രിയ വിശ്വാസ ചടങ്ങ്. പൗലൊ "ഞാൻ തൃപ്തനാകാൻ പഠിച്ചു" — ഇത് ജന്മ ശീലം അല്ല, ആത്മ വഴി ആർജ്ജിക്കൽ. ഈ പഠനം അത്യാഗ്രഹ വേര്, തൃപ്തി സൗന്ദര്യ, ദൈവ ജീവ ആനന്ദ കണ്ടെത്തൽ — ഇവ ആഴ്‌ചിക്കൽ ഉൾക്കൊള്ളും.',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440003', 'hi',
   'बाइबल अनुसार प्रबंधन',
   'बाइबल की एक मूलभूत शिक्षा यह है: पृथ्वी प्रभु की है और उसमें जो कुछ है — हम मालिक नहीं, प्रबंधक हैं। यह नज़रिया सब कुछ बदल देता है — हम पैसा कैसे कमाते हैं, कैसे खर्च करते हैं, कैसे बचाते हैं और कैसे देते हैं। एक प्रबंधक अपने मालिक को जवाब देता है — एक दिन हम परमेश्वर को जवाब देंगे कि हमने उनके संसाधनों का क्या किया। यीशु के तालंत के दृष्टान्त में प्रबंधन की इस जवाबदेही को स्पष्ट रूप से दिखाया गया है। यह अध्ययन पैसे, समय, प्रतिभा और संबंधों — सभी को परमेश्वर की सुपुर्दगी के रूप में देखने का बाइबलीय ढाँचा देता है।',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440003', 'ml',
   'ബൈബിൾ ഭരണം',
   'ബൈബിൾ ഒരു അടിസ്ഥാന ഉപദേശം: ഭൂമി കർത്താവിന്റേതും അതിലുള്ളതൊക്കെ — നാം ഉടമകളല്ല, ഭരണക്കാരാണ്. ഈ ദർശനം ഒക്കെ മാറ്റുന്നു — പണം എങ്ങനെ സമ്പാദിക്കുന്നു, ചെലവ്, ലാഭ, ദാനം — ഇവ ഒക്കെ. ഒരു ഭരണക്കൻ ഉടമക്ക് ഉത്തരം ചൊല്ലണം — ഒരു ദിനം നാം ദൈവ ദാനം ഉപയോഗ വിധം ദൈവ മുൻ ഉത്തരം ചൊല്ലും. യേശുവിന്റെ തൻ്ററ്റ് ഉപമ ഈ ഉത്തരവാദ ഭരണ ദൗത്യം വ്യക്തമാക്കുന്നു. ഈ പഠനം പണം, സമയം, കഴിവ്, ബന്ധം — ഒക്കെ ദൈവ ദൗത്യ ദൃഷ്ടിയിൽ കാണുന്ന ബൈബിൾ ചട്ടക്കൂട് നൽകും.',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440004', 'hi',
   'दशांश और दान',
   'दशांश — अपनी आय का दसवाँ भाग — पुराने नियम में इस्राएल की व्यवस्था का हिस्सा था, लेकिन उदार देने का सिद्धांत नए नियम में और गहरा हो जाता है। यीशु ने दशांश को गलत नहीं कहा, बल्कि उसके आगे न्याय, दया और विश्वास को भी माँगा (मत्ती 23:23)। पौलुस ने 2 कुरिन्थियों 9 में कहा: "जो खुशी से देता है उसे परमेश्वर प्यार करता है" — देना आनंद से होना चाहिए, मज़बूरी से नहीं। देना विश्वास का एक कार्य है — यह कहता है "मुझे परमेश्वर की व्यवस्था पर भरोसा है।" इस अध्ययन में दशांश की बाइबलीय आधार, मसीही देने के सिद्धांत और देने में आनंद खोजने का तरीका समझें।',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440004', 'ml',
   'ദശാംശവും ദാനവും',
   'ദശാംശം — വരുമാനം ഒരു ദശ ഭാഗം — പഴയ നിയമ ഇസ്രായേൽ ഉടമ്പടി ഭാഗം, ഉദാര ദാന ഉദ്ദേശ്യം പുതിയ നിയമ ൽ ആഴ്‌ചിക്കൽ ആകുന്നു. ദശാംശം ഗ്രഹ പ്രകാരം ആകരുത് — "നീതി, കരുണ, വിശ്വാസം" ഇവ ഒക്കെ ആവശ്യം (മത്തായി 23:23). 2 കൊരിന്ത്യർ 9 ൽ: "സന്തോഷ ദാതാവ് ദൈവ ഇഷ്ടൻ" — ദാനം ആനന്ദ ദൗത്യം, നിർബ്ബന്ധ ദൗത്യം അല്ല. ദാനം ഒരു വിശ്വാസ കർമ്മം — "ദൈവ കരുതൽ ഞാൻ വിശ്വസിക്കുന്നു" എന്ന് പ്രഖ്യാപിക്കൽ. ദശാംശ ബൈബിൾ ആധാരം, ക്രൈസ്തവ ദാന ഉദ്ദേശ്യ, ദാനം ആനന്ദ കണ്ടെത്തൽ — ഈ പഠനം ഇവ ഉൾക്കൊള്ളും.',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440005', 'hi',
   'काम, कमाई और परमेश्वर की व्यवस्था',
   'काम पाप के बाद का अभिशाप नहीं — यह पतन से पहले परमेश्वर ने आदम को बाग की देखभाल के लिए दिया था (उत्पत्ति 2:15)। काम परमेश्वर के स्वभाव में भागीदारी का एक तरीका है — परमेश्वर एक काम करने वाले सर्जक हैं और हम उनके स्वरूप में बने हैं। ईमानदार मेहनत, उचित वेतन, कर्मचारियों के साथ न्याय — ये सब बाइबलीय मूल्य हैं जो परमेश्वर के चरित्र को दर्शाते हैं। यह अध्ययन यह भी पूछता है: क्या मेरे काम करने का तरीका परमेश्वर को सम्मान देता है? आलस्य, लोभ और अनुचित व्यवहार — इनसे कैसे बचें? काम एक आत्मिक अनुशासन और एक बुलाहट है, न केवल जीविका का साधन।',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440005', 'ml',
   'ജോലി, സമ്പാദ്യം, ദൈവ കരുതൽ',
   'ജോലി പതനത്തിനു ശേഷം ഉണ്ടായ ശാപം അല്ല — ഉൽപ്പത്തി 2:15-ൽ പതനത്തിനു മുൻ ദൈവം ആദത്തിന് ഉദ്യാനം സൂക്ഷിക്കാൻ ദൗത്യം ഏൽപ്പിച്ചു. ജോലി ദൈവ സ്വഭാവ ഭാഗ ദൗത്യം — ദൈവം ഒരു സൃഷ്ടിക്കുന്ന ദൈവം, നാം ദൈവ ഛായ. ആത്മ പ്രയത്നം, ന്യായ വേതനം, ജോലി നീതി — ഇവ ദൈവ ചരിത്ര ദർശനം. ഞാൻ ജോലി ചെയ്യുന്ന വിധം ദൈവ ആദരം നൽകുന്നോ? — ഈ ചോദ്യം ഈ പഠനം ഉന്നയിക്കുന്നു. ജോലി ഒരു ആത്മ ദൗത്യം, ഒരു ദൈവ വിളി — ജീവ മാർഗ്ഗം മാത്രമല്ല.',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440006', 'hi',
   'अनंत निवेश',
   'मत्ती 6:19-21 में यीशु की सीधी बात: "पृथ्वी पर अपने लिए धन इकट्ठा मत करो... परंतु स्वर्ग में अपने लिए धन इकट्ठा करो।" यह वित्तीय सलाह नहीं बल्कि एक हृदय परिवर्तन की बुलाहट है — क्योंकि "जहाँ तुम्हारा खजाना है, वहाँ तुम्हारा दिल भी है।" अनंत के लिए निवेश में शामिल है: उदार देना जो परमेश्वर के काम को आगे बढ़ाता है, लोगों में निवेश करना जो अनंत तक जाते हैं, और वे बलिदान जो इस जीवन से परे फल देते हैं। यह दुनिया के वित्तीय तर्क को उलट देता है — इस जीवन में खर्च करने से अगले जीवन में समृद्ध होना। इस अध्ययन में जानें कि अनंत दृष्टिकोण से देखने पर पैसे, समय और जीवन का अर्थ कैसे बदल जाता है।',
   'Christian Living'),

  ('fff00000-e29b-41d4-a716-446655440006', 'ml',
   'നിത്യ നിക്ഷേപം',
   'മത്തായി 6:19-21 ൽ യേശുവിന്റെ ആഴ വചനം: "ഭൂമിയിൽ നിക്ഷേ ശേഖ രിക്കരുത്... സ്വർഗ്ഗത്തിൽ ശേഖരിക്കുക." ഇത് സാമ്പത്തിക ഉപദേശം അല്ല — ഹൃദ മനം മാറ്റ ആഹ്വാനം, "നിക്ഷേ ഇരിക്കുന്നിടം ഹൃദ ഇരിക്കും." ശാശ്വത നിക്ഷേ ഉൾക്കൊള്ളുന്നത്: ദൈവ ദൗത്യ ഉദ്ദേശ്യ ഉദ്ദേശ്യ, ശാശ്വത ജീവ ഉൾക്കൊള്ളുന്ന ആൾ നിക്ഷേ, ഈ ജീവ അതീത ഫലം ഉൽപ്പാദിക്കുന്ന ത്യാഗ. ഇത് ലോക സാമ്പത്തിക യുക്തി തലകീഴ് ആക്കുന്നു — ഈ ജീവ ചെലവ്, അടുത്ത ജീവ സമ്പന്നം. ശാശ്വത ദർശനം പണം, സമയം, ജീവ അർത്ഥം — ഇവ മാറ്റുന്ന വിധം ഈ പഠനം ഉൾക്കൊള്ളും.',
   'Christian Living')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- KKK: Historical Reliability of the Bible (5 topics)
-- Note: ab500000..001-005 content = KKK topics from migration 20260223
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('ab500000-e29b-41d4-a716-446655440001', 'hi',
   'नए नियम के प्राचीन लेखन प्रमाण',
   'नया नियम इतिहास में सबसे अधिक प्रमाणित प्राचीन दस्तावेज़ है — 5,800 से अधिक यूनानी हस्तलिपियाँ, साथ में 10,000 से अधिक लैटिन और अन्य भाषाओं की हस्तलिपियाँ। तुलना के लिए: होमर की इलियड की केवल 643 हस्तलिपियाँ हैं, फिर भी इसकी ऐतिहासिकता पर कोई सवाल नहीं करता। पांडुलिपियाँ घटनाओं के बहुत करीब की हैं — सबसे प्रारंभिक हस्तलिपि खंड (P52) यूहन्ना के सुसमाचार के लगभग 25-30 वर्षों के भीतर का है। टेक्सचुअल स्कॉलर्स का अनुमान है कि नए नियम का 99.5% मूल पाठ सुरक्षित है। यह अध्ययन उन लोगों के लिए है जो जानना चाहते हैं कि क्या आज की बाइबल वास्तव में वही है जो पहले लिखी गई थी।',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440001', 'ml',
   'പുതിയ നിയമ പ്രാചീന ലേഖന തെളിവ്',
   'പുതിയ നിയമം ചരിത്രത്തിലെ ഏറ്റവും നന്നായി സ്ഥിരീകരിക്കപ്പെട്ട പ്രാചീന ഗ്രന്ഥം — 5,800-ലധികം ഗ്രീക്ക് കൈ ലേഖ, 10,000-ലധികം ലത്തീൻ, ഇതര ഭാഷ ലേഖ. തട്ടേ: ഹോമർ ഇലിയഡ് 643 ലേഖ മാത്രം, എന്നിട്ടും ചരിത്ര ബോദ്ധ്യ ചോദ്യ ഇല്ല. ആദ്യ ലേഖ ഖണ്ഡം (P52) — യോഹ. സുവിശേഷം 25-30 വർഷ ഉൾ. ടെക്സ്ചൽ ഗവേഷകർ: 99.5% മൂല ലേഖ സംരക്ഷിത. ഇന്ന് ഉള്ള ബൈബിൾ ആദ്യ ലേഖ ആണ് — ഇത് അറിയാൻ ആഗ്രഹിക്കുന്നവർക്ക് ഈ പഠനം ആഴ്‌ചിക്കൽ ഉൾക്കൊള്ളും.',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440002', 'hi',
   'बाइबल की पुरातात्विक पुष्टि',
   'पिछले 150 वर्षों में पुरातत्व ने बार-बार बाइबल की ऐतिहासिक सटीकता को सिद्ध किया है — उन विवरणों की भी जिन्हें आलोचकों ने कभी काल्पनिक कहा था। हित्तियों का अस्तित्व — जिसे एक बार बाइबलीय आविष्कार कहा गया था — पुरातत्व ने 1906 में खोज कर पुष्टि की। पोन्तियुस पिलातुस के शिलालेख (1961), दाऊद के घराने का उल्लेख (1993 में टेल दान शिलालेख), और जेरिको की दीवारें — ये सब बाइबलीय अभिलेखों से मेल खाते हैं। पुरातत्व बाइबल को "सिद्ध" नहीं कर सकता, लेकिन यह अनगिनत बार यह दिखाता है कि बाइबल के लेखक वास्तविक इतिहास लिख रहे थे।',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440002', 'ml',
   'ബൈബിളിന്റെ പുരാവസ്തു തെളിവ്',
   'കഴിഞ്ഞ 150 വർഷ പുരാവസ്തു ഗവേഷണം ആവർത്തിച്ച് ബൈബിൾ ചരിത്ര കൃത്യത സ്ഥിരീകരിക്കുന്നു — ഒരു കാലം ഐതിഹ്യം എന്ന് നിരാകരിക്കപ്പെട്ടതൊക്കെ. ഹിത്ത്യർ — ഒരു കാലം ബൈബിൾ ആഖ്യാനം — 1906-ൽ കണ്ടെത്തി. പൊന്തിയൊസ് പീലാത്തൊസ് ലിഖിതം (1961), ദാവീദ് ഗൃഹ ഉദ്ദേശ്യ (1993 ടെൽ ദാൻ ലിഖിതം), യെരിക്കോ മതിൽ — ഇവ ബൈബിൾ ആഖ്യാനം ഒത്ത് ചേരുന്നു. പുരാവസ്തു ബൈബിൾ "തെളിയിക്കാൻ" ആകില്ല, പക്ഷേ ബൈബിൾ ലേഖകർ ഹൃദ ചരിത്രം ആഖ്യാനിക്കുകയായിരുന്നു — ഇത് ആവർത്തിച്ച് ദൃഷ്ടിഗോചരം.',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440003', 'hi',
   'मसीह में पूरी हुई पुराने नियम की भविष्यवाणियाँ',
   'पुराने नियम में 300 से अधिक विशिष्ट भविष्यवाणियाँ यीशु के जन्म से सदियों पहले लिखी गईं और उनके जीवन, मृत्यु और पुनरुत्थान में पूरी हुईं। बेतलहम में जन्म (मीका 5:2), कुँवारी से जन्म (यशायाह 7:14), गधे पर यरुशलेम में प्रवेश (जकर्याह 9:9), 30 चाँदी के टुकड़ों के लिए बेचा जाना (जकर्याह 11:12-13), हड्डियाँ न तोड़ी जाना (भजन 34:20) — ये सब यीशु में सटीक रूप से पूरी हुईं। किसी एक व्यक्ति द्वारा 8 भविष्यवाणियाँ संयोग से पूरी होने की संभावना 10 की घात 17 में एक है। यह बाइबल के दिव्य प्रेरणा और यीशु की मसीहाई पहचान के लिए सबसे शक्तिशाली प्रमाणों में से एक है।',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440003', 'ml',
   'ക്രിസ്തുവിൽ നിറവേറിയ പഴയ നിയമ പ്രവചനങ്ങൾ',
   'പഴയ നിയമ 300-ലധികം വ്യക്തിഗത പ്രവചനങ്ങൾ യേശുവിന്റെ ജനനത്തിന് നൂറ്റാണ്ടുകൾ മുൻ ലേഖനം — അദ്ദേഹ ജീവ-മരണ-പുനരുത്ഥ നിറ. ബേത്‌ലഹം ജനനം (മീഖ 5:2), കന്യക ജനനം (യശ. 7:14), കഴുത ജറൂ. പ്രവേശം (സെക്. 9:9), 30 വെള്ളി വഞ്ചന (സെക്. 11:12-13), അസ്ഥി ഭഞ്ജനം ഇല്ല (സങ്കീ. 34:20) — ഇവ ഒക്കെ കൃത്യ. 8 പ്രവചനം ഒരൊററ ആൾ ആകസ്മ നിറ — 10 ഘാതം 17-ൽ ഒരു. ബൈബിൾ ദൈവ നിശ്വ, യേശുവിന്റെ ക്രിസ്ത ഐഡൻ്ററ്റ — ഇതിന്റെ ഏറ്റവും ശക്ത തെളിവ്.',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440004', 'hi',
   'इतिहास में पुनरुत्थान',
   'यीशु का पुनरुत्थान मसीही विश्वास की आधारशिला है — और पौलुस ने कहा: "यदि मसीह नहीं जी उठा तो तुम्हारा विश्वास व्यर्थ है" (1 कुरिन्थियों 15:17)। पुनरुत्थान के लिए ऐतिहासिक साक्ष्य: खाली कब्र (जिसे यहूदी नेता और रोमन सैनिक कभी अस्वीकार नहीं कर पाए, केवल चोरी का आरोप लगाया), 500 से अधिक लोगों को एक साथ दर्शन (1 कुरिन्थियों 15:6), और शिष्यों का कायापलट — भयभीत और छिपे हुए लोगों का साहसी शहीद बनना। इन तथ्यों की सबसे अच्छी व्याख्या वास्तविक पुनरुत्थान है। यह अध्ययन आपको पुनरुत्थान के ऐतिहासिक प्रमाण देता है जो विश्वास को कारण पर टिकाता है।',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440004', 'ml',
   'ചരിത്ര സത്യമായ പുനരുത്ഥാനം',
   'യേശു പുനരുത്ഥ ക്രൈസ്തവ വിശ്വ ആണി കല്ല് — "ക്രിസ്തു ഉയർക്കായ്കിൽ വിശ്വ ശൂന്യ" (1 കൊ. 15:17). പുനരുത്ഥ ചരിത്ര തെളിവ്: ശൂന്യ കല്ലറ (യഹൂദ നേതൃ-റോമ ഭടൻ ഒരിക്കലും നിഷേ ആകിയില്ല — കൊ. ആരോ ആക്ക മാത്രം), 500-ലധികം ആൾ ഒരുമിച്ച് ദർശ (1 കൊ. 15:6), ഭയ-ഒളി ശിഷ്യ ധൈര്യ രക്ത സാക്ഷ ആകൽ. ഈ വസ്തുതകൾക്ക് ഏറ്റവും ഉചിത ആഖ്യ: ഹൃദ പുനരുത്ഥ. ഈ പഠനം പുനരുത്ഥ ചരിത്ര തെളിവ് — കാരണ ആധാര വിശ്വ — ഇത് ഉൾക്കൊള്ളും.',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440005', 'hi',
   'बाइबल का संग्रह कैसे बना',
   '"कैनन" शब्द का अर्थ है माप की छड़ — वे पुस्तकें जो माप की कसौटी पर खरी उतरीं। ये 66 पुस्तकें क्यों बाइबल में हैं और दूसरी नहीं? आरंभिक कलीसिया ने तीन मुख्य कसौटियों का उपयोग किया: अपोस्तलीयता (प्रत्यक्ष प्रेरित संबंध), बाइबलीय सहमति (शेष पवित्रशास्त्र से मेल), और व्यापक उपयोग (चर्चों में स्वीकृति)। अपोक्रिफा जैसी पुस्तकें इन कसौटियों पर पूरी नहीं उतरीं। यह एक बैठक में नहीं हुआ — सदियों में प्रमाण देखकर कलीसिया ने मान्यता दी। यह अध्ययन बताएगा कि यह प्रक्रिया कैसे काम की और हम आज इस पर विश्वास क्यों रख सकते हैं।',
   'Apologetics'),

  ('ab500000-e29b-41d4-a716-446655440005', 'ml',
   'ബൈബിൾ ശേഖരം എങ്ങനെ രൂപപ്പെട്ടു',
   '"കാനൺ" (Canon) ശബ്ദത്തിന്റെ അർത്ഥം അളക്കൽ ദണ്ഡ് — ആ ദണ്ഡ് ഒത്ത് ചേർന്ന 66 പുസ്തകങ്ങൾ ബൈബിളിൽ ഉൾപ്പെടുത്തി, ബാക്കി ഒഴിവ് — ഇതെന്തുകൊണ്ട്? ആദ്യ സഭ മൂന്ന് മുഖ്യ മാനദണ്ഡം ഉപയോഗിച്ചു: അപ്പൊസ്തലിക ബന്ധം, ബൈബിൾ ഐക്യം, സഭ വ്യാപക ഉപയോഗം. ആ മാനദണ്ഡം ഒത്ത് ചേർന്നില്ലാത്ത ഗ്രന്ഥം ഒഴിവ്. ഒറ്റ ഉൾ ആക്കൽ ഇല്ല — നൂറ്റാണ്ടുകൾ ആഴ ഗവേഷണം, ദൈവ ആത്മ അംഗീകാരം. ഈ പ്രക്രിയ എങ്ങനെ ഉണ്ടായി, ഇന്ന് ഇത് ആശ്രയിക്കാൻ ഒരുവൻ എന്തുകൊണ്ട് — ഈ പഠനം ഇത് ഉൾക്കൊള്ളും.',
   'Apologetics')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- Hebrews 6-13 (ab500000..006-013)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('ab500000-e29b-41d4-a716-446655440006', 'hi',
   'इब्रानियों 6: परिपक्वता की ओर बढ़ें',
   'इब्रानियों 6 में नए नियम की सबसे कठिन चेतावनी है: जो लोग आत्मा के काम को अनुभव करने के बाद विश्वास छोड़ देते हैं, उनका मन फिर से पश्चाताप के लिए नहीं लौटाया जा सकता। लेकिन लेखक यह भी कहता है कि उसे अपने पाठकों के बारे में "बेहतर बातें" की आशा है। यह चेतावनी भय फैलाने के लिए नहीं बल्कि आगे बढ़ने के लिए है। जो सच्चे विश्वास में हैं उनके लिए यह निराशा का नहीं बल्कि दृढ़ता का बुलावा है। इस अध्ययन में समझें कि यह कठिन अंश वास्तव में क्या कह रहा है और एक विश्वासी को आगे कैसे बढ़ाता है।',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440006', 'ml',
   'എബ്രായർ 6: പക്വതയിലേക്ക് മുന്നേറുക',
   'പുതിയ നിയമത്തിലെ ഏറ്റവും കഠിനമായ മുന്നറിയിപ്പ് എബ്രായർ 6-ൽ ഉണ്ട്: ആത്മാവിന്റെ ദാനം ആസ്വദിച്ച ശേഷം വിശ്വാസം ഉപേക്ഷിക്കുന്നവരെ വീണ്ടും അനുതാപത്തിലേക്ക് മടക്കി കൊണ്ടുവരാൻ ആകില്ല. എന്നിട്ടും ലേഖകൻ പറയുന്നു: "നിങ്ങളെക്കുറിച്ച് ഇതിലും നല്ലതാണ് ഞങ്ങൾ ഉറ്ററിയുന്നത്." ഈ മുന്നറിയിപ്പ് ഭയം ഉണ്ടാക്കാനല്ല — മുന്നോട്ട് നടക്കൽ, ദൃഢതയോടെ പിടിക്കൽ ഇതിനു വേണ്ടി. ക്രിസ്തുവിൽ ആശ്രയിക്കുന്നവർക്ക് ഇത് നൈരാശ്യ-ക്ഷണം അല്ല, ഉറ്റ-ദൃഢതയുടെ ആഹ്വാനം. ഈ കഠിന-ഭാഗം യഥാർത്ഥത്തിൽ എന്ത് പറയുന്നു, ഒരു വിശ്വാസിയെ ഇത് മുന്നോട്ട് എങ്ങനെ നടത്തുന്നു — ഈ പഠനം ഇത് ഉൾക്കൊള്ളും.',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440007', 'hi',
   'मेल्कीसेदेक की याजकाई',
   'यीशु मसीह एक शाश्वत याजक हैं — न लेवीय वंश से, बल्कि मेल्कीसेदेक के क्रम के अनुसार, जिस याजक का बाइबल में न आरंभ बताया गया है न अंत। लेवीय याजक बार-बार बलिदान चढ़ाते थे क्योंकि मृत्यु उन्हें काट देती थी। लेकिन यीशु सदा जीता है और इसलिए अपनी याजकाई को सदा के लिए धारण करता है — वह अंत तक बचाने में सक्षम है। यीशु अभी भी हमारे लिए परमेश्वर के सामने मध्यस्थता कर रहा है। यह अध्ययन दिखाता है कि यीशु लेवीय व्यवस्था से कितना श्रेष्ठ है और उसकी मध्यस्थता का हमारे लिए क्या अर्थ है।',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440007', 'ml',
   'മെൽക്കീസേദക്കിന്റെ പൗരോഹിത്യം',
   'യേശു ക്രിസ്തു ഒരു ശാശ്വത പുരോഹിതൻ — ലേവ്യ വംശത്തിൽ നിന്നല്ല, മറിച്ച് മെൽക്കീസേദക്കിന്റെ ക്രമത്തിൽ, ആ പുരോഹിതന്റെ ആരംഭവും അവസാനവും ബൈബിൾ വ്യക്തമാക്കിയിട്ടില്ല. ലേവ്യ പുരോഹിതർ ആവർത്തിച്ച് ബലി അർപ്പിച്ചു, കാരണം മരണം അവരെ ഇടർച്ചപ്പെടുത്തിക്കൊണ്ടിരുന്നു. എന്നാൽ യേശു എന്നേക്കും ജീവിക്കുന്നതിനാൽ, അവന്റെ പൗരോഹിത്യം ശാശ്വതം — ഒടുവോളം ദൈവ-സന്നിധിയിൽ നമ്മുക്കായി ഇടനിൽക്കുന്നു. ലേവ്യ ക്രമത്തേക്കാൾ ക്രിസ്തുവിന്റെ ഉന്നത്വവും ആ ഇടനിൽ-ദൗത്യം നമ്മുക്ക് എന്ത് അർഥം — ഈ പഠനം ഇവ ഉൾക്കൊള്ളും.',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440008', 'hi',
   'एक बेहतर वाचा',
   'लेवीय याजकाई अपूर्ण थी इसलिए परमेश्वर ने यिर्मयाह के द्वारा एक नई वाचा का वादा किया — जहाँ व्यवस्था पत्थर की शिलाओं पर नहीं बल्कि हृदयों पर लिखी जाएगी, पाप पूरी तरह क्षमा किए जाएंगे, और परमेश्वर की प्रजा उसे व्यक्तिगत रूप से जानेगी। "नई वाचा" की घोषणा यह दिखाती है कि पहली वाचा अस्थायी थी। पुरानी वाचा की हर प्रतिज्ञा का "हाँ" मसीह में मिलती है जो बेहतर वाचा के मध्यस्थ हैं। यह अध्ययन बताएगा कि परमेश्वर ने नई वाचा में क्या दिया और इसका हमारे दैनिक जीवन के लिए क्या अर्थ है।',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440008', 'ml',
   'ഒരു ഉത്തമ ഉടമ്പടി',
   'ലേവ്യ പൗരോഹിത്യം അപൂർണ്ണമായിരുന്നു, അതിനാൽ ദൈവം യിർമ്മ്യ വഴി ഒരു പുതിയ ഉടമ്പടി വാഗ്ദത്തം ചെയ്തു — ശിലകളിലല്ല ഹൃദയത്തിൽ ആലേഖനം ചെയ്യുന്ന, പാപം പൂർണ്ണമായി ക്ഷമിക്കുന്ന, ദൈവ-ജനം ദൈവത്തെ വ്യക്തിപരമായി അറിയുന്ന ഒരു ഉടമ്പടി. ദൈവം "പഴയ ഉടമ്പടി" കടന്ന് "പുതിയ" ഉടമ്പടി ഘോഷിക്കുന്നത് ആദ്യ ഉടമ്പടി കടന്നുപോകും എന്ന് കാണിക്കുന്നു. ഒന്നാം ഉടമ്പടിയിലെ ഓരോ വാഗ്ദത്തവും ക്രിസ്തുവിൽ "അതേ" ആകുന്നു, കാരണം അവൻ ഉത്തമ ഉടമ്പടിയുടെ ഇടനിൽക്കാരൻ. ദൈവം ഈ ഉടമ്പടിയിൽ നൽകിയത് എന്ത്, ഇത് നമ്മുടെ ദൈനംദിന ജീവിതത്തിൽ എന്ത് അർഥം — ഈ പഠനം ഇവ ഉൾക്കൊള്ളും.',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440009', 'hi',
   'स्वर्गीय पवित्रस्थान',
   'पृथ्वी का तंबू स्वर्गीय पवित्रस्थान की केवल एक छाया और नकल था। मसीह मनुष्यों के बनाए पवित्रस्थान में नहीं, बल्कि स्वर्ग में परमेश्वर के सामने हमारी ओर से प्रकट हुआ। पुराने बलिदान अंतःकरण को शुद्ध नहीं कर सकते थे — वे प्रतिवर्ष दोहराए जाते थे क्योंकि वे अपर्याप्त थे। लेकिन मसीह ने एक बार अपने आप को बलिदान चढ़ाकर अनंत छुटकारा प्राप्त किया। एक सिद्ध बलिदान ने सभी बलिदानों को समाप्त कर दिया — यही इब्रानियों का हृदय-सत्य है।',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440009', 'ml',
   'സ്വർഗ്ഗീയ വിശുദ്ധ മണ്ഡലം',
   'ഭൗമ-കൂടാരം സ്വർഗ്ഗീയ വിശുദ്ധ-മണ്ഡലത്തിന്റെ ഒരു നിഴലും നകലും മാത്രമായിരുന്നു. ക്രിസ്തു മനുഷ്യ-നിർമ്മിത വിശുദ്ധ-മണ്ഡലത്തിലല്ല, നമ്മുക്കായി സ്വർഗ്ഗത്തിൽ ദൈവ-സന്നിധിയിൽ പ്രത്യക്ഷപ്പെട്ടു. പഴയ ബലികൾ ആന്തരിക-ശുദ്ധി നൽകിയില്ല — അവ അപര്യാപ്തമായിരുന്നതിനാൽ ആണ്ടോടാണ്ട് ആവർത്തിക്കേണ്ടിവന്നു. എന്നാൽ ക്രിസ്തു ഒറ്റ-ബലിയിൽ ശാശ്വത-വീണ്ടെടുപ്പ് നേടി. ഒരു പൂർണ്ണ-ബലി ഒക്കെ ബലിക്കും പകരമായി — ഇതാണ് എബ്രായർ ലേഖനത്തിന്റെ ഹൃദയ-സത്യം.',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440010', 'hi',
   'एक बार सदा के लिए',
   'एक ही बलिदान से मसीह ने हमेशा के लिए उन लोगों को सिद्ध किया जो पवित्र किए जा रहे हैं। जहाँ पाप क्षमा हो गए, वहाँ और बलिदान की ज़रूरत नहीं। इब्रानियों की चौथी चेतावनी यहाँ है: मसीह के लहू के द्वारा निकट आओ, एकत्र होना मत छोड़ो, और जानबूझकर सच्चाई जानने के बाद पाप करने से सावधान रहो। यह जानबूझकर किया गया पाप रोमियों 7 की चल रही जद्दोजहद नहीं, बल्कि मसीह के बलिदान को जान-बूझकर ठुकराना है। इस अध्ययन में देखें कि क्रूस का एकमात्र सिद्ध बलिदान हमें पूरी तरह बचाता है।',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440010', 'ml',
   'ഒരിക്കൽ, ശാശ്വതമായി',
   'ഒറ്റ ബലിയിൽ ക്രിസ്തു ശുദ്ധീകരിക്കപ്പെടുന്നവരെ ശാശ്വതമായി പൂർണ്ണരാക്കി. പാപം ക്ഷമിക്കപ്പെട്ടിടത്ത്, ഇനി ബലി ആവശ്യമില്ല. എബ്രായർ ലേഖനത്തിന്റെ നാലാം മുന്നറിയിപ്പ് ഇവിടെ ഉണ്ട്: ക്രിസ്തുവിന്റെ രക്തം വഴി അടുത്ത് ചെല്ലുക, ഒന്നിച്ചുള്ള ആരാധന ഉപേക്ഷിക്കരുത്, ബോധ-പൂർവ്വം സത്യം അറിഞ്ഞ ശേഷം പാപം ചെയ്യുന്നതിൽ ജാഗ്രത. ആ ബോധ-പൂർവ്വ-പാപം റോമർ 7-ലെ ഉൾ-പോരാട്ടമല്ല — ക്രിസ്തുവിന്റെ ബലിയെ ബോധ-പൂർവ്വം തള്ളിക്കളയൽ. കുരിശിന്റെ പൂർണ്ണ-ബലി നമ്മെ പൂർണ്ണമായി രക്ഷിക്കുന്നത് — ഈ പഠനത്തിൽ കണ്ടെത്തുക.',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440011', 'hi',
   'विश्वास की गैलरी',
   'विश्वास उन बातों का भरोसा है जिनकी आशा है और उन बातों का प्रमाण है जो दिखती नहीं। इब्रानियों 11 में हाबेल, हनोक, नूह, अब्राहम, सारा, इसहाक, याकूब, यूसुफ, मूसा और राहाब जैसे लोगों की परेड है — सभी ने जो मिला नहीं था उसकी आशा रखते हुए परमेश्वर पर भरोसा किया। वे वीर उपलब्धियों के नहीं बल्कि कष्ट, यातना और मृत्यु में भी टिके रहने वाले विश्वास के उदाहरण हैं। उन्होंने वादों को दूर से देखा और उन्हें नमस्कार किया। यह अध्ययन दिखाता है कि विश्वास हमेशा आशा पर टिका रहता है, न कि परिस्थितियों पर।',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440011', 'ml',
   'വിശ്വാസ ഗ്യാലറി',
   'വിശ്വാസം — പ്രതീക്ഷിക്കുന്നതിന്റെ ഉറ്റ-ബോദ്ധ്യം, കാണാൻ ആകാത്തതിന്റെ തെളിവ്. എബ്രായർ 11-ൽ ഹാബേൽ, ഹനോക്ക്, നോഹ, അബ്രഹാം, സാറ, ഇസ്ഹാക്ക്, യാക്കോബ്, ജോസഫ്, മോശ, രാഹാബ് — ഇവർ ഓരോരുത്തരും ലഭിക്കാതിരുന്ന വാഗ്ദത്തത്തിൽ ദൈവത്തിൽ ആശ്രയിച്ചവർ. ഇവർ ധീര-നേട്ടത്തിന്റെ ഉദാഹരണം മാത്രമല്ല — കഷ്ടം, ദ്രോഹം, മരണം ഇവ നടുവിലും ഉറ്റ-ദൃഢതയോടെ നിൽക്കുന്ന വിശ്വാസത്തിന്റെ ഉദാഹരണം. ദൂരെ നിന്ന് വാഗ്ദത്തം കണ്ട്, ആ വാഗ്ദത്തത്തിനോ നമസ്ക്കരിച്ചവർ. വിശ്വാസം എപ്പോഴും സാഹചര്യങ്ങളിലല്ല, പ്രത്യാശയിൽ ആശ്രയിക്കുന്നു — ഈ പഠനം ഇത് കാണിക്കുന്നു.',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440012', 'hi',
   'दौड़ में बने रहना',
   'इसलिए, जब हम गवाहों के ऐसे बड़े बादल से घिरे हुए हैं (अध्याय 11 के विश्वास के नायक), तो हर बोझ और पाप को दूर करके, यीशु की ओर देखते हुए, धैर्य के साथ दौड़ें जो हमारे आगे रखी है। परमेश्वर उन्हें अनुशासित करते हैं जिनसे वह प्रेम करते हैं — हमारी भलाई के लिए कि हम उनकी पवित्रता में भाग लें। समुदाय को शांति, पवित्रता और उस कृपा में चलने की बुलाहट है जो असफल नहीं होती। यीशु विश्वास का आरंभ करने वाला और सिद्ध करने वाला है — उसी पर नज़र टिकाए रखना दौड़ का रहस्य है।',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440012', 'ml',
   'ഓട്ടം തുടരുക',
   'ഇത്ര വലിയ സാക്ഷ്യ-സമൂഹം (11-ാം അദ്ധ്യായത്തിലെ വിശ്വാസ-നായകർ) നമ്മെ ചുറ്റി-നിൽക്കുന്നതിനാൽ, ഓരോ ഭാരവും പാപവും ഉപേക്ഷിച്ച്, യേശുവിലേക്ക് നോക്കി, ക്ഷമയോടെ നമ്മുടെ മുൻപ് ഇരിക്കുന്ന ഓട്ടം ഓടുക. ദൈവം സ്നേഹിക്കുന്നവരെ ശിക്ഷണം ചെയ്യുന്നു — നമ്മുടെ നന്മക്ക്, അവന്റെ വിശുദ്ധിയിൽ നാം പങ്കാളിയാകാൻ. സഭ-സമൂഹം സമാധാനം, വിശുദ്ധി, പരാജയ-ഇല്ലാത്ത കൃപ ഇവ ഉൾക്കൊണ്ട് നടക്കണം. യേശു വിശ്വാസത്തിന്റെ ആരംഭ-കാരണനും പൂർത്തിക്കുന്നവനും — അവനിൽ ദൃഷ്ടി ഉറപ്പിക്കൽ ഓട്ടത്തിന്റെ രഹസ്യം.',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440013', 'hi',
   'अंतिम शिक्षाएँ',
   'इब्रानियों का अंत व्यावहारिक शिक्षाओं से होता है: अजनबियों को आतिथ्य दो, कैदियों को याद रखो, विवाह का सम्मान करो, धन के प्रेम से मुक्त रहो, अपने अगुओं को याद करो और उनके विश्वास की नकल करो। चरमोत्कर्ष मसीहीय है: यीशु ने अपने लहू से लोगों को पवित्र करने के लिए फाटक के बाहर दुख उठाया — इसलिए हम भी उसकी निंदा उठाते हुए उसके पास शिविर के बाहर जाएं। स्तुति का बलिदान सभी पुराने बलिदानों का स्थान लेता है। इस अध्ययन में देखें कि इब्रानियों की पूरी शिक्षा रोज़मर्रा के जीवन में कैसे लागू होती है।',
   'Foundations of Faith'),

  ('ab500000-e29b-41d4-a716-446655440013', 'ml',
   'അന്ത്യ ഉപദേശങ്ങൾ',
   'എബ്രായർ ലേഖനം പ്രായോഗിക ഉപദേശങ്ങളോടെ അവസാനിക്കുന്നു: അതിഥികൾക്ക് ആദരവ് നൽകുക, തടവ്-ശ്രദ്ധ, വിവാഹം ബഹുമാനിക്കുക, പണ-ആഗ്രഹത്തിൽ നിന്ന് സ്വതന്ത്രരാകുക, നിങ്ങളുടെ നേതാക്കളെ ഓർക്കുകയും അവരുടെ വിശ്വാസം അനുകരിക്കുകയും ചെയ്യുക. ഏറ്റവും ഉന്നത ഭാഗം: യേശു ജനത്തെ ശുദ്ധീകരിക്കാൻ കവാടത്തിന് പുറത്ത് കഷ്ടം അനുഭവിച്ചു — അതിനാൽ നാമും അവന്റെ നിന്ദ വഹിച്ച് ശിബിരത്തിന് പുറത്ത് അവന്റെ അടുക്കൽ ചെല്ലാം. സ്തുതി-ബലി ഒക്കെ പഴയ ബലിക്കും പകരമായി. ഈ ലേഖനത്തിലെ ഉപദേശം ദൈനംദിന-ജീവിതത്തിൽ എങ്ങനെ — ഈ പഠനം ഇത് ഉൾക്കൊള്ളും.',
   'Foundations of Faith')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- LLL: Cults / False Teaching (ab600000..001-003)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('ab600000-e29b-41d4-a716-446655440001', 'hi',
   'झूठी शिक्षा क्या होती है?',
   'बाइबलीय भाषा का उपयोग करने वाली हर शिक्षा बाइबलीय नहीं होती। गलातियों, 2 पतरस और 1 यूहन्ना में झूठी शिक्षा की पहचान के लिए मज़बूत उपकरण मिलते हैं। झूठी शिक्षा आमतौर पर यीशु की पहचान, अनुग्रह के सुसमाचार या शास्त्र के अधिकार को तोड़-मरोड़ देती है। पहचानने के चिह्न: बाइबल के बाहर से नया प्रकाशन, मानवीय प्रयास से उद्धार, और अगुवे पर अंधा भरोसा। यह ज्ञान विश्वास की परिपक्वता का चिह्न है — हर अच्छे लगने वाले संदेश की जाँच करना ज़रूरी है।',
   'Apologetics'),

  ('ab600000-e29b-41d4-a716-446655440001', 'ml',
   'തെറ്റായ ഉപദേശം എന്നാൽ എന്ത്?',
   'ബൈബിൾ-ഭാഷ ഉപയോഗിക്കുന്ന ഓരോ ഉപദേശവും ബൈബിൾ-ആധാരം ഉള്ളതല്ല. ഗലാത്യർ, 2 പത്രോസ്, 1 യോഹന്നാൻ ഇവ തെറ്റായ ഉപദേശം തിരിച്ചറിയാൻ ശക്തമായ ഉപകരണങ്ങൾ നൽകുന്നു. തെറ്റായ ഉപദേശം പൊതുവെ യേശുവിന്റെ ആത്മ-ഭാവം, കൃപ-സുവിശേഷം, തിരുവെഴുത്തിന്റെ അധികാരം ഇവ വക്രപ്പെടുത്തുന്നു. അടയാളങ്ങൾ: ബൈബിളിന് പുറത്ത് നിന്ന് നിർദ്ദേശം, മനുഷ്യ-പ്രയത്നം വഴി രക്ഷ, നേതൃ-ആശ്രിത-അന്ധ-ആശ്രയം. ഓരോ നല്ലതോന്നൽ-ഉള്ള ഉപദേശവും ശോധന-ചെയ്യൽ വിശ്വാസ-പക്വതയുടെ ചിഹ്നം.',
   'Apologetics'),

  ('ab600000-e29b-41d4-a716-446655440002', 'hi',
   'संप्रदायों के सामान्य पैटर्न',
   'संप्रदाय अपनी विशेष मान्यताओं से अलग, कुछ सामान्य पैटर्न साझा करते हैं: बाइबल के बाहर से अधिकार, मनुष्य के प्रयास से उद्धार, बाहरी लोगों से अलगाव, और एक विशेष समूह की पहचान। यहोवा साक्षियों, मॉर्मनवाद जैसे समूहों में इन पैटर्न को पहचानना सीखें। इन लोगों के पास सुसमाचार के सत्य और वास्तविक प्रेम के साथ पहुँचने के लिए तैयार हों। धार्मिक भ्रम में फँसे लोगों से बात करना डरावना नहीं, प्रेम-आधारित मिशन है। इस अध्ययन में सीखें कि बिना नफ़रत के, केवल सत्य और प्रेम के साथ, इन समूहों के लोगों से कैसे बातचीत करें।',
   'Apologetics'),

  ('ab600000-e29b-41d4-a716-446655440002', 'ml',
   'വ്യാജ മത-സമൂഹങ്ങളുടെ പൊതു-രീതികൾ',
   'വ്യാജ-സഭകൾ അവരുടെ പ്രത്യേക വിശ്വാസങ്ങൾ ഒഴിവ് ചെയ്താൽ, ചില പൊതു-രീതികൾ പങ്കിടുന്നു: ബൈബിൾ-ഇതര അധികാരം, മനുഷ്യ-പ്രയത്നം-വഴി-രക്ഷ, ബാഹ്യർക്ക് ഒറ്റ-പെടൽ, ഒരു പ്രത്യേക-ഗ്രൂപ്പ്-ആത്മ. യഹോവ-സാക്ഷികൾ, മോർമ്മൻ-പ്രസ്ഥാനം ഇവയിൽ ഈ രീതി തിരിച്ചറിയൽ പഠിക്കുക. ഈ ആളുകളെ സുവിശേഷ-സത്യവും യഥാർഥ-സ്നേഹവും ഉള്ളതോടെ സമീപിക്കാൻ ഒരുങ്ങുക. മത-ഭ്രമത്തിൽ കുടുങ്ങിയവരോട് സംസാരിക്കൽ ഭയ-ജനകമല്ല, സ്നേഹ-ആധാരിത-ദൗത്യം. ദ്വേഷം ഇല്ലാതെ, സത്യവും സ്നേഹവും ഉൾക്കൊണ്ട് ഈ ഗ്രൂപ്പ്-ആളുകളോട് എങ്ങനെ — ഈ പഠനം ഇത് ഉൾക്കൊള്ളും.',
   'Apologetics'),

  ('ab600000-e29b-41d4-a716-446655440003', 'hi',
   'अनुग्रह बनाम कर्म-आधारित धर्म',
   'हर झूठा धर्म — मसीहियत के विकृत रूपों सहित — अंततः ईश्वरीय अनुग्रह पाने के लिए मानवीय प्रयास की माँग करता है। मसीही सुसमाचार की मौलिक विशिष्टता यह है: उद्धार केवल अनुग्रह से, केवल विश्वास से, केवल मसीह में — किसी मानवीय योग्यता के बिना। यह सत्य असली मसीहियत और हर धार्मिक नकल के बीच की सबसे स्पष्ट रेखा है। गलातियों में पौलुस ने इसी सत्य के लिए लड़ाई की क्योंकि यह सुसमाचार का हृदय है। इस अध्ययन में जानें कि कर्म-आधारित धर्म और अनुग्रह-आधारित सुसमाचार में क्या फर्क है।',
   'Foundations of Faith'),

  ('ab600000-e29b-41d4-a716-446655440003', 'ml',
   'കൃപ vs. പ്രവൃത്തി-ആധാരിത-മതം',
   'ക്രൈസ്തവതയുടെ വക്രപ്പെട്ട രൂപങ്ങൾ ഉൾപ്പടെ ഓരോ വ്യാജ-മതവും, ദൈവ-കൃപ നേടാൻ മനുഷ്യ-പ്രയത്നം ആവശ്യപ്പെടുന്നു. ക്രൈസ്തവ-സുവിശേഷത്തിന്റെ മൗലിക-സവിശേഷത: കൃപ-മാത്രം, വിശ്വാസം-മാത്രം, ക്രിസ്തുവിൽ-മാത്രം — ഒരു മനുഷ്യ-യോഗ്യത ഇല്ലാതെ. ഈ സത്യം യഥാർഥ-ക്രൈസ്തവതക്കും ഏതൊരു മത-അനുകരണത്തിനും ഇടക്കുള്ള ഏറ്റവും വ്യക്തമായ വരയാണ്. ഗലാത്യർ ലേഖനത്തിൽ പൗലോസ് ഈ സത്യത്തിനായി പോരാടി, കാരണം ഇത് സുവിശേഷത്തിന്റെ ഹൃദയം. പ്രവൃത്തി-ആധാരിത-മതവും കൃപ-ആധാരിത-സുവിശേഷവും തമ്മിലുള്ള വ്യത്യാസം ഈ പഠനത്തിൽ മനസ്സിലാകും.',
   'Foundations of Faith')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- MMM: Christianity and Culture (ab700000..001-005)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('ab700000-e29b-41d4-a716-446655440001', 'hi',
   'मसीही संस्कृति से कैसे जुड़ते हैं?',
   'इतिहास में मसीहियों ने संस्कृति से अलग-अलग तरीकों से जुड़ाव किया है — उससे हट जाना, उसके अनुरूप हो जाना, उसे बदलने की कोशिश करना, या रचनात्मक तनाव में रहना। बाइबल की रोशनी में इन तरीकों की जाँच करें और समझदारी, ज्ञान और सुसमाचार के इरादे के साथ संस्कृति में शामिल होने का एक विचारशील ढाँचा विकसित करें। यह अध्ययन पूछता है: मसीही होना मेरे सांस्कृतिक जुड़ाव को कैसे बदलता है? क्या मैं दुनिया से भाग रहा हूँ या उसमें सुसमाचार की रोशनी लेकर जा रहा हूँ? यह विषय हर मसीही के लिए प्रासंगिक है जो दुनिया में जीते हुए दुनिया का नहीं बनना चाहता।',
   'Christian Living'),

  ('ab700000-e29b-41d4-a716-446655440001', 'ml',
   'ക്രൈസ്തവർ സംസ്കാരവുമായി ഇടപെടുന്നത് എങ്ങനെ?',
   'ചരിത്രത്തിൽ ക്രൈസ്തവർ സംസ്കാരവുമായി ഭിന്ന-രീതികളിൽ ഇടപെട്ടിരിക്കുന്നു — അതിൽ നിന്ന് ഒഴിഞ്ഞ്-മാറൽ, അനുകൂലിക്കൽ, അത് മാറ്റാൻ ശ്രമിക്കൽ, ക്രിയാത്മക-ബന്ധം. ബൈബിൾ-വെളിച്ചത്തിൽ ഈ രീതികൾ പരിശോധിക്കുക, ജ്ഞാനം-ബുദ്ധി-സുവിശേഷ-ഉദ്ദേശ്യം ഉൾക്കൊണ്ട് സംസ്കാരത്തിൽ ഭാഗം-ചേരൽ-ചട്ടം വികസിപ്പിക്കുക. ഈ പഠനം ചോദ്യം: ക്രൈസ്തവൻ ആകൽ എന്റെ സാംസ്കാരിക-ഇടപെടൽ എങ്ങനെ മാറ്റുന്നു? ഞാൻ ലോകത്തിൽ നിന്ന് ഓടി-മാറുകയോ ലോകത്തിൽ സുവിശേഷ-വെളിച്ചം കൊണ്ടുചെല്ലുകയോ ചെയ്യുന്നു? ലോകത്തിൽ ജീവിക്കുമ്പോൾ ലോകത്തിന്റേത് ആകാൻ ആഗ്രഹിക്കാത്ത ഓരോ ക്രൈസ്തവനും ഈ വിഷയം പ്രസക്തം.',
   'Christian Living'),

  ('ab700000-e29b-41d4-a716-446655440002', 'hi',
   'मीडिया, मनोरंजन और विवेक',
   'हम जो देखते-सुनते हैं वह हमें आकार देता है। फिलिप्पियों 4:8, भजन 101 और रोमियों 12:2 पर आधारित एक बाइबलीय ढाँचा विकसित करें — नियमों की सूची नहीं बल्कि सोचने का तरीका। सही सवाल: यह क्या सामान्य बनाता है? यह मुझमें क्या आकार दे रहा है? यह परमेश्वर की संतान के रूप में मेरी पहचान से कैसे मेल खाता है? यह अध्ययन मीडिया को न पूरी तरह अस्वीकार करता है न बिना सोचे स्वीकार करता है — बल्कि एक परिपक्व, बाइबलीय दृष्टि विकसित करने में मदद करता है।',
   'Christian Living'),

  ('ab700000-e29b-41d4-a716-446655440002', 'ml',
   'മാധ്യമം, വിനോദം, ആത്മ-വിവേചനം',
   'നാം കാണുകയും കേൾക്കുകയും ചെയ്യുന്നത് നമ്മെ രൂപ-പ്പെടുത്തുന്നു. ഫിലിപ്പ്യർ 4:8, സങ്കീർത്തനം 101, റോമർ 12:2 ഇവ ആധാരമായി ഒരു ബൈബിൾ-ചട്ടം വികസിപ്പിക്കുക — നിയമ-പട്ടിക അല്ല, ചിന്ത-രീതി. ശരിയായ ചോദ്യം: ഇത് എന്ത് സ്വഭാവം-സ്ഥിരമാക്കുന്നു? ഇത് എന്നിൽ ഏത് ആകൃതി ഉണ്ടാക്കുന്നു? ദൈവ-മക്കൾ ആയ എന്റെ ആത്മ-ഭാവവുമായി ഇത് ചേർന്നുപോകുന്നുണ്ടോ? ഈ പഠനം മാധ്യമം പൂർണ്ണ-നിരാകരണം ചെയ്യുന്നില്ല, ആലോചന ഇല്ലാതെ ഉൾക്കൊള്ളൽ ചെയ്യുന്നില്ല — പൂർണ്ണ ബൈബിൾ-ദൃഷ്ടി വികസിക്കാൻ സഹായിക്കും.',
   'Christian Living'),

  ('ab700000-e29b-41d4-a716-446655440003', 'hi',
   'लैंगिकता और बाइबलीय नीतिशास्त्र',
   'लैंगिकता पर बाइबल की शिक्षा समकालीन संस्कृति के बिल्कुल विपरीत है — न इसलिए कि मसीहियत दमनकारी है, बल्कि इसलिए कि परमेश्वर का स्वरूप अच्छा है। सृष्टि में लैंगिकता का बाइबलीय दर्शन पढ़ें, पतन ने इसे कैसे विकृत किया, और सुसमाचार कैसे पुनर्स्थापित और छुड़ाता है। बाइबलीय विश्वासों को स्पष्टता और करुणा दोनों के साथ रखना सीखें। यह अध्ययन उन लोगों के लिए है जो इस विषय पर परमेश्वर के दृष्टिकोण को समझना चाहते हैं।',
   'Christian Living'),

  ('ab700000-e29b-41d4-a716-446655440003', 'ml',
   'ലൈംഗികതയും ബൈബിൾ-നൈതികശാസ്ത്രവും',
   'ലൈംഗികതയെക്കുറിച്ചുള്ള ബൈബിൾ ഉദ്ദേശ്യം ഇന്നത്തെ സംസ്കാരത്തിൽ നിന്ന് തികച്ചും വ്യത്യസ്തം — ക്രൈസ്തവത അടിച്ചമർത്തലുള്ളതായതുകൊണ്ടല്ല, ദൈവ-സ്വഭാവം ഉത്തമം ആണ്. സൃഷ്ടിയിൽ ലൈംഗികതയുടെ ബൈബിൾ-ദർശനം, പതനം ഇതിനെ എങ്ങനെ വക്രപ്പെടുത്തി, സുവിശേഷം എങ്ങനെ ഉദ്ധരിക്കുകയും പുനഃ-സ്ഥാപിക്കുകയും ചെയ്യുന്നു. ബൈബിൾ-വിശ്വാസങ്ങൾ വ്യക്തതയോടും കാരുണ്യത്തോടും ഒന്നിച്ച് ഉറ്ററിഞ്ഞ്-നിൽക്കൽ പഠിക്കുക. ഈ വിഷയത്തിൽ ദൈവ-ദൃഷ്ടി മനസ്സിലാക്കാൻ ആഗ്രഹിക്കുന്നവർക്ക് ഈ പഠനം.',
   'Christian Living'),

  ('ab700000-e29b-41d4-a716-446655440004', 'hi',
   'न्याय, दया और सुसमाचार',
   'बाइबल गरीबों, कमज़ोरों और पीड़ितों की गहरी परवाह करती है। लेकिन बाइबलीय न्याय विचारधारा से नहीं, सुसमाचार से बहता है। शास्त्र क्या कहता है न्याय और दया के बारे में, कलीसिया को हाशिये पर पड़े लोगों की सेवा के लिए कैसे बुलाया गया है, और दो त्रुटियों से कैसे बचें: अन्याय को नज़रअंदाज़ करना या सुसमाचार को सामाजिक कार्यवाद से बदलना। यह अध्ययन मसीह का एक संतुलित, बाइबलीय दृष्टि देता है जो न्याय और अनुग्रह दोनों की माँग करता है।',
   'Mission & Evangelism'),

  ('ab700000-e29b-41d4-a716-446655440004', 'ml',
   'നീതി, കരുണ, സുവിശേഷം',
   'ബൈബിൾ ദരിദ്രരോടും ദുർബ്ബലരോടും ദ്രോഹം-ഏറ്റവർക്കോടും ആഴമായ ശ്രദ്ധ കാണിക്കുന്നു. എന്നാൽ ബൈബിൾ-നീതി ആദർശ-ചിന്തയിൽ നിന്നല്ല, സുവിശേഷ-ഹൃദയത്തിൽ നിന്ന് ഒഴുകുന്നു. നീതിയെയും കരുണയെയും കുറിച്ച് ദൈവ-വചനം എന്ത് പറയുന്നു, ഹൃദ-ദൂരത്തിലുള്ളവർക്ക് സഭ ശ്രദ്ധ-നൽകൽ, രണ്ട് പിഴവ് ഒഴിവ്: അനീതി-അവഗണന, സുവിശേഷം-സാമൂഹ്യ-പ്രവർത്തനം-ആക്കൽ. ഈ പഠനം ക്രിസ്തുവിൻ ക്രമ-ബൈബിൾ-ദൃഷ്ടി നൽകുന്നു, ഒന്നിൽ നിന്ന് ഒഴുകി മറ്റൊന്ന് ഉൾക്കൊള്ളുന്ന, നീതിയും കൃപയും ചേർന്ന ഒരു ദർശനം.',
   'Mission & Evangelism'),

  ('ab700000-e29b-41d4-a716-446655440005', 'hi',
   'सत्य को प्रेम से बोलना',
   'एफिसियों 4:15 विश्वासियों को प्रेम से सत्य बोलने की बुलाहट करता है — दोनों प्रतिबद्धताओं को किसी एक की कीमत पर नहीं बल्कि साथ-साथ। एक ऐसी संस्कृति में जो अक्सर विश्वास को नफ़रत और प्रेम को अनुमोदन मानती है, यह एक नाज़ुक और महत्वपूर्ण बुलाहट है। जटिल विषयों को बाइबलीय स्पष्टता, वास्तविक देखभाल और सुसमाचार की विनम्र साहस के साथ संबोधित करना सीखें। सत्य और प्रेम एक-दूसरे के विरोधी नहीं हैं — मसीह इन दोनों का पूर्ण उदाहरण है।',
   'Christian Living'),

  ('ab700000-e29b-41d4-a716-446655440005', 'ml',
   'സ്നേഹത്തോടെ സത്യം പറയൽ',
   'എഫേസ്യർ 4:15 വിശ്വാസികളെ സ്നേഹത്തോടെ സത്യം പറയാൻ ആഹ്വാനം ചെയ്യുന്നു — ഒന്ന് ഒഴിവ്-ചെയ്ത് മറ്റൊന്ന് അല്ല, രണ്ടും ഒന്നിച്ച്. വിശ്വാസത്തെ ദ്വേഷ്യം-ആക്കൽ, സ്നേഹത്തെ അംഗീകാരം-ആക്കൽ ഇവ ചെയ്യുന്ന സംസ്കാരത്തിൽ ഇത് ഒരു നിർണ്ണായക-ആഹ്വാനം. ബൈബിൾ-വ്യക്തത, യഥാർഥ-ശ്രദ്ധ, സുവിശേഷ-വിനയ-ധൈര്യം ഇവ ഉൾക്കൊണ്ട് സങ്കീർണ്ണ-വിഷയങ്ങൾ കൈകാര്യം ചെയ്യൽ പഠിക്കുക. സത്യവും സ്നേഹവും പരസ്പര-വിരോധം അല്ല — ക്രിസ്തു ഈ രണ്ടിന്റെയും പൂർണ്ണ-ഉദാഹരണം.',
   'Christian Living')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- NNN: Singleness, Dating, and Marriage (ab800000..001-004)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('ab800000-e29b-41d4-a716-446655440001', 'hi',
   'विवाह के लिए परमेश्वर का स्वरूप',
   'विवाह पतन से पहले परमेश्वर ने रचा था — एक पुरुष और एक स्त्री के बीच वाचा जो मसीह के कलीसिया के प्रति प्रेम को दर्शाती है। बाइबलीय विवाह की धार्मिक नींव — उसका उद्देश्य, ढाँचा और बलिदानमय स्वभाव — पढ़ें। परमेश्वर के स्वरूप को समझना विवाह को केवल सामाजिक संस्था या व्यक्तिगत सुविधा तक सीमित होने से बचाता है। यह अध्ययन उन सभी के लिए है जो विवाह को परमेश्वर की नज़र से देखना चाहते हैं — चाहे अविवाहित हों या विवाहित।',
   'Family & Relationships'),

  ('ab800000-e29b-41d4-a716-446655440001', 'ml',
   'വിവാഹത്തിന്റെ ദൈവ-സ്വരൂപം',
   'വിവാഹം പതനത്തിന് മുൻ ദൈവം സൃഷ്ടിച്ചു — ഒരു പുരുഷനും ഒരു സ്ത്രീക്കും ഇടക്ക് ഒരു ഉടമ്പടി, ക്രിസ്തു തന്റെ സഭക്ക് നൽകുന്ന സ്നേഹം ദർശിക്കുന്ന. ബൈബിൾ-വിവാഹത്തിന്റെ ദൈവ-ശാസ്ത്ര-അടിത്തറ — ഉദ്ദേശ്യം, ഘടന, ത്യാഗ-സ്വഭാവം ഇവ പഠിക്കുക. ദൈവ-സ്വരൂപം മനസ്സിലാക്കൽ വിവാഹത്തെ ഒരു സാമൂഹ്യ-സ്ഥാപനം മാത്രം, അല്ലെങ്കിൽ വ്യക്തിഗത-സൗകര്യം മാത്രം ആകുന്നതിൽ നിന്ന് തടഞ്ഞ്-നിർത്തുന്നു. ദൈവ-ദൃഷ്ടിയിൽ വിവാഹം കാണാൻ ആഗ്രഹിക്കുന്ന ഓരോർക്കും ഈ പഠനം — അവിവാഹിതർ ആണെങ്കിലും വിവാഹിതർ ആണെങ്കിലും.',
   'Family & Relationships'),

  ('ab800000-e29b-41d4-a716-446655440002', 'hi',
   'विवाह से पहले पवित्रता',
   'लैंगिक पवित्रता पुरानी नियम नहीं है — यह सुसमाचार का प्रतिबिंब है — परमेश्वर ने हमारे शरीर को महँगी कीमत से खरीदा इसलिए उसे उससे सम्मान दें। पवित्रता का बाइबलीय दर्शन पढ़ें, यह आत्मिक और संबंधात्मक रूप से क्यों महत्वपूर्ण है, और अत्यधिक लैंगिक संस्कृति में इसे व्यावहारिक रूप से कैसे खोजें। पवित्रता केवल संयम के बारे में नहीं है — यह परमेश्वर और भावी जीवनसाथी का सम्मान करने के बारे में है।',
   'Family & Relationships'),

  ('ab800000-e29b-41d4-a716-446655440002', 'ml',
   'വിവാഹത്തിന് മുൻ ലൈംഗിക-പരിശുദ്ധി',
   'ലൈംഗിക-പരിശുദ്ധി ഒരു പഴഞ്ചൻ-നിയമം അല്ല — ഇത് സുവിശേഷ-ദർപ്പണം: ദൈവം വലിയ-വിലക്ക് നമ്മുടെ ശരീരം വാങ്ങി, അതിനാൽ ആ ശരീരം കൊണ്ട് ദൈവത്തെ ബഹുമാനിക്കുക. ബൈബിൾ-ദർശനം: ആത്മ-ബന്ധ-ജീവൻ ഉൾ ഇത് ഏതുകൊണ്ടാണ് നിർണ്ണായകം, അതി-ലൈംഗിക-സംസ്കാരത്തിൽ ഇത് പ്രായോഗികമായി ഏതുരൂപത്തിൽ. ലൈംഗിക-പരിശുദ്ധി കേവലം-സംയമം ആകൃതിയിലല്ല — ദൈവത്തെയും ഭാവി-ജീവിത-പങ്കാളിയെയും ബഹുമാനിക്കൽ ആണ്. ഈ സംസ്കൃതി-കാലത്ത് ഇത് ജീവൻ-ആകൃതി ചെയ്യൽ — ഈ പഠനം ഇത് ഉൾക്കൊള്ളും.',
   'Family & Relationships'),

  ('ab800000-e29b-41d4-a716-446655440003', 'hi',
   'जीवनसाथी का बुद्धिमानी से चुनाव',
   'किससे विवाह करना है — यह जीवन के सबसे महत्वपूर्ण निर्णयों में से एक है। शास्त्र क्या कहता है जीवनसाथी में खोजने वाले गुणों के बारे में — साझा विश्वास, चरित्र, परमेश्वरभक्तता — और बुद्धि, प्रार्थना और जवाबदेही के साथ इस विवेक की प्रक्रिया से कैसे गुज़रें। लक्ष्य सिद्ध साथी नहीं, बल्कि एक विश्वासयोग्य वाचा-साथी है। यह अध्ययन उन सभी के लिए है जो किसी रिश्ते में हैं या भविष्य में विवाह के बारे में सोच रहे हैं।',
   'Family & Relationships'),

  ('ab800000-e29b-41d4-a716-446655440003', 'ml',
   'ജീവിത-പങ്കാളിയെ ജ്ഞാനത്തോടെ തിരഞ്ഞെടുക്കൽ',
   'ആരെ വിവാഹം ചെയ്യണം — ഇത് ജീവിതത്തിലെ ഏറ്റവും നിർണ്ണായക-തീരുമാനം. ജീവിത-പങ്കാളിയിൽ തിരഞ്ഞ് ഏതൊക്കെ ഗുണം — സഹ-വിശ്വാസം, സ്വഭാവം, ദൈവ-ഭക്തി — ഇവ ദൈവ-വചനം ആരോടും-ചൊല്ലുന്നു. ജ്ഞാനം, പ്രാർഥന, ഉത്തരവാദ-ബന്ധം ഇവ ഉൾക്കൊണ്ട് ഈ ശ്രദ്ധ-കൂടുതൽ-ഉണ്ടാക്കൽ-പ്രക്രിയ മുന്നോട്ടു കൊണ്ടുപോക്ക്. ലക്ഷ്യം പൂർണ്ണ-പങ്കാളി അല്ല, ഒരു വിശ്വസ്ത-ഉടമ്പടി-പങ്കാളി. ഒരു ബന്ധത്തിൽ ഉള്ളവർക്കും ഭാവി-വിവാഹം ചിന്തിക്കുന്നവർക്കും ഈ പഠനം.',
   'Family & Relationships'),

  ('ab800000-e29b-41d4-a716-446655440004', 'hi',
   'जब विवाह कठिन हो जाए',
   'हर विवाह में संघर्ष, निराशा और कठिनाई के मौसम आते हैं। सुसमाचार बने रहने की दोनों प्रेरणा और संसाधन देता है — क्षमा, नम्रता, बलिदानमय प्रेम और पवित्र आत्मा की शक्ति। शास्त्र क्या कहता है वैवाहिक कठिनाइयों को समझने, वाचा की गंभीरता, और कब और कैसे मदद लेनी है। यह अध्ययन दिखाता है कि कठिन विवाह भी परमेश्वर की कृपा और दोनों पक्षों की प्रतिबद्धता से फल सकता है।',
   'Family & Relationships'),

  ('ab800000-e29b-41d4-a716-446655440004', 'ml',
   'വിവാഹം പ്രയാസകരമാകുമ്പോൾ',
   'ഓരോ വിവാഹത്തിലും സംഘർഷങ്ങളുടെയും നിരാശകളുടെയും കഠിനമായ ഘട്ടങ്ങൾ വരും. സുവിശേഷം നിലനിൽക്കാനുള്ള പ്രചോദനവും വിഭവങ്ങളും നൽകുന്നു — ക്ഷമ, എളിമ, ത്യാഗപൂർണ്ണമായ സ്നേഹം, പരിശുദ്ധാത്മാവിന്റെ ശക്തി എന്നിവ ഉൾപ്പെടെ. വൈവാഹിക ബുദ്ധിമുട്ടുകൾ മനസ്സിലാക്കാനും ഉടമ്പടിയുടെ ഗൗരവം അറിയാനും എപ്പോൾ, എങ്ങനെ സഹായം തേടണം എന്നും തിരുവചനം നമ്മോട് പഠിപ്പിക്കുന്നു. ദൈവകൃപയും ഇരുകൂട്ടരുടെയും പ്രതിബദ്ധതയും ഉണ്ടെങ്കിൽ കഠിനമായ ഒരു വിവാഹബന്ധം പോലും സഫലമാകുമെന്ന് ഈ പഠനം കാണിച്ചുതരുന്നു.',
   'Family & Relationships')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- OOO: Mental Health, Emotions, and the Gospel (ab900000..001-005)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('ab900000-e29b-41d4-a716-446655440001', 'hi',
   'बाइबल में भावनाएँ: परमेश्वर ने हमें भावनाएँ दीं',
   'परमेश्वर भावनाहीन नहीं हैं, और न ही हम — हम उनके स्वरूप में बने हैं। बाइबल कैसे मानवीय भावनाओं की एक विस्तृत श्रृंखला को चित्रित करती है — आनंद, दुख, क्रोध, भय, लालसा — यह समझें। भावनाएँ दबाने की दुश्मन नहीं बल्कि समझने के संकेत हैं। सुसमाचार हमें पूरे व्यक्ति के रूप में संबोधित करता है — शरीर, मन और हृदय। यह अध्ययन उन लोगों के लिए है जो अपनी भावनाओं को परमेश्वर के स्वरूप में समझना चाहते हैं।',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440001', 'ml',
   'ബൈബിളിൽ വികാരങ്ങൾ: ദൈവം നമുക്ക് വികാരങ്ങൾ തന്നു',
   'ദൈവം വികാരരഹിതനല്ല, നാമും അങ്ങനെ ആകേണ്ടതില്ല — കാരണം നാം അവന്റെ സ്വരൂപത്തിൽ സൃഷ്ടിക്കപ്പെട്ടവരാണ്. സന്തോഷം, ദുഃഖം, കോപം, ഭയം, ആഗ്രഹം എന്നിങ്ങനെ മനുഷ്യ വികാരങ്ങളുടെ വിശാലമായ ശ്രേണി ബൈബിൾ എങ്ങനെ ചിത്രീകരിക്കുന്നുവെന്ന് ഈ പഠനം വ്യക്തമാക്കുന്നു. വികാരങ്ങൾ അടിച്ചമർത്തേണ്ട ശത്രുക്കളല്ല, മറിച്ച് നമ്മുടെ ആന്തരിക അവസ്ഥ അറിയിക്കുന്ന അടയാളങ്ങളാണ്. സുവിശേഷം നമ്മെ ശരീരം, മനസ്സ്, ഹൃദയം എന്നിവ ഉൾക്കൊള്ളുന്ന ഒരു സമ്പൂർണ്ണ വ്യക്തിയായി അഭിസംബോധന ചെയ്യുന്നു.',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440002', 'hi',
   'चिंता, फ़िक्र और परमेश्वर की शांति',
   'चिंता हमारे समय की सबसे सामान्य समस्याओं में से एक है — और बाइबल सीधे इस पर बात करती है। फिलिप्पियों 4, मत्ती 6 और 1 पतरस 5 में बाइबलीय प्रतिक्रिया समझें: चिंता को खारिज करना नहीं बल्कि प्रार्थना, इनकार नहीं बल्कि परमेश्वर की व्यवस्था और प्रेम की ओर पुनर्अभिमुखीकरण। परमेश्वर की शांति हृदयों को उन तरीकों से सुरक्षित रखती है जो समझ से परे हैं। यह अध्ययन दिखाता है कि बाइबलीय चिंता प्रबंधन केवल "चिंता मत करो" कहना नहीं है।',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440002', 'ml',
   'ഉത്കണ്ഠ, വിഷമം, ദൈവത്തിന്റെ സമാധാനം',
   'ഉത്കണ്ഠ നമ്മുടെ കാലത്തെ ഏറ്റവും സാധാരണമായ പ്രശ്നങ്ങളിൽ ഒന്നാണ്, ബൈബിൾ ഇതിനെ നേരിട്ട് അഭിമുഖീകരിക്കുന്നു. ഫിലിപ്പിയർ 4, മത്തായി 6, 1 പത്രോസ് 5 എന്നിവയിൽ ബൈബിൾ നൽകുന്ന ഉത്തരം ഇതാണ്: ഉത്കണ്ഠയെ തള്ളിക്കളയുകയല്ല, പ്രാർഥനയിലൂടെ ദൈവത്തിലേക്ക് തിരിയുക, നിഷേധിക്കുകയല്ല, ദൈവത്തിന്റെ പരിചരണത്തിലും സ്നേഹത്തിലും ശ്രദ്ധ കേന്ദ്രീകരിക്കുക. ദൈവത്തിന്റെ സമാധാനം നമ്മുടെ ഹൃദയങ്ങളെ മനുഷ്യ ബുദ്ധിക്ക് അതീതമായ വിധത്തിൽ കാത്തുരക്ഷിക്കുന്നു.',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440003', 'hi',
   'अवसाद और आत्मा',
   'बाइबल के कई नायकों — एलिय्याह, दाऊद, यिर्मयाह — ने गहरे अंधकार और निराशा का अनुभव किया। शास्त्र उन्हें इसके लिए शर्मिंदा नहीं करता। यह अध्ययन अवसाद को एक बाइबलीय दृष्टिकोण से ईमानदारी से संबोधित करता है: इसकी वास्तविकता को स्वीकार करना, इसके आत्मिक और शारीरिक आयामों की खोज करना, और उस परमेश्वर की ओर इशारा करना जो हमारी सबसे निचली घाटी में भी हमारे साथ है।',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440003', 'ml',
   'വിഷാദവും ആത്മാവും',
   'ബൈബിളിലെ പല നായകന്മാരും — ഏലിയാ, ദാവീദ്, യിരെമ്യാ — ആഴമായ അന്ധകാരവും നിരാശയും അനുഭവിച്ചിട്ടുണ്ട്. എന്നാൽ തിരുവചനം അതിന് അവരെ നാണംകെടുത്തുന്നില്ല. ഈ പഠനം വിഷാദത്തെ ബൈബിൾ കാഴ്ചപ്പാടിൽ സത്യസന്ധമായി നേരിടുന്നു: അതിന്റെ യാഥാർഥ്യം അംഗീകരിക്കുക, അതിന്റെ ആത്മീയവും ശാരീരികവുമായ മാനങ്ങൾ പരിശോധിക്കുക, നമ്മുടെ ഏറ്റവും ആഴമേറിയ താഴ്വരകളിലും നമ്മോടൊപ്പം ഉള്ള ദൈവത്തിലേക്ക് ചൂണ്ടുക. ഈ ദൈവം ദുർബലരെ തള്ളിക്കളയാതെ അവരോടൊപ്പം ഇരിക്കുന്നവനാണ്.',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440004', 'hi',
   'शोक, विलाप और उपचार',
   'शोक हानि के प्रति एक पवित्र और ज़रूरी प्रतिक्रिया है — और बाइबल हमें शोक करने की पूरी अनुमति देती है। विलाप का बाइबलीय अध्ययन पढ़ें, यीशु ने लाज़र की कब्र पर कैसे रोए, और भजन दुख को परमेश्वर के पास लाने को कैसे आदर्श बनाते हैं। शोक करना विश्वास की कमी नहीं है। परमेश्वर टूटे हृदय वालों के निकट हैं।',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440004', 'ml',
   'ദുഃഖം, വിലാപം, സൗഖ്യം',
   'ദുഃഖം നഷ്ടത്തോടുള്ള ഒരു പരിശുദ്ധവും ആവശ്യകവുമായ പ്രതികരണമാണ്, ബൈബിൾ നമ്മെ ദുഃഖിക്കാൻ പൂർണ്ണ അനുവാദം നൽകുന്നു. വിലാപ പുസ്തകത്തിന്റെ ബൈബിൾ പഠനം, ലാസറിന്റെ കല്ലറയ്ക്കൽ യേശു കരഞ്ഞ സംഭവം, ദുഃഖം ദൈവത്തിന്റെ അടുക്കൽ കൊണ്ടുചെല്ലുന്നത് സങ്കീർത്തനങ്ങൾ എങ്ങനെ മാതൃകയാക്കുന്നു എന്നിവ ഈ പഠനം അന്വേഷിക്കുന്നു. ദുഃഖിക്കുന്നത് വിശ്വാസക്കുറവിന്റെ അടയാളമല്ല. ദൈവം തകർന്ന ഹൃദയങ്ങളുള്ളവരോടൊപ്പം അടുത്ത് ഇരിക്കുന്നവനാണ്.',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440005', 'hi',
   'वह आशा जो निराश नहीं करती',
   'रोमियों 5 घोषणा करता है कि आशा हमें शर्मिंदा नहीं करती क्योंकि परमेश्वर का प्रेम हमारे हृदयों में उँडेला गया है। यह अध्ययन संघर्ष करने वाली आत्मा को सुसमाचार की अटल आशा में लंगर करता है — परिस्थितियों पर आधारित आशावाद नहीं बल्कि परमेश्वर कौन हैं और मसीह ने क्या किया इस पर आधारित निश्चितता।',
   'Christian Living'),

  ('ab900000-e29b-41d4-a716-446655440005', 'ml',
   'നിരാശപ്പെടുത്താത്ത പ്രത്യാശ',
   'റോമർ 5 പ്രഖ്യാപിക്കുന്നത്, ദൈവത്തിന്റെ സ്നേഹം നമ്മുടെ ഹൃദയങ്ങളിൽ പകർന്നിരിക്കുന്നതിനാൽ ആ പ്രത്യാശ നമ്മെ ലജ്ജിപ്പിക്കുകയില്ല എന്നാണ്. ഈ പഠനം, ബുദ്ധിമുട്ടനുഭവിക്കുന്ന ആത്മാക്കളെ സുവിശേഷത്തിന്റെ ഉറച്ച പ്രത്യാശയിൽ നങ്കൂരമിടുന്നു. ഇത് സാഹചര്യങ്ങളെ അടിസ്ഥാനമാക്കിയ ശുഭാപ്തിവിശ്വാസമല്ല, മറിച്ച് ദൈവം ആരാണെന്നും ക്രിസ്തു എന്ത് ചെയ്തുവെന്നും അടിസ്ഥാനമാക്കിയ ഉറച്ച നിശ്ചയമാണ്. ഈ പ്രത്യാശ ജീവിതത്തിന്റെ ഏത് കൊടുങ്കാറ്റിലും നമ്മെ നിലനിർത്തും.',
   'Christian Living')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- PPP: Friendship and Christian Community (aba00000..001-002)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('aba00000-e29b-41d4-a716-446655440001', 'hi',
   'बाइबल में आत्मिक मित्रता',
   'बाइबल गहरी मित्रता का उत्सव मनाती है — दाऊद और योनातान, रूत और नाओमी, पौलुस और तीमुथियुस — परमेश्वर के महान उपहारों में से एक के रूप में। बाइबलीय मित्रता कैसी दिखती है: आपसी प्रतिबद्धता, ईमानदार परामर्श, साझा विश्वास, और कठिनाई में टिकने वाला प्रेम। यह सीखें कि आत्मिक मित्रता मसीही जीवन के लिए एक विलासिता नहीं बल्कि एक आवश्यकता है।',
   'Church & Community'),

  ('aba00000-e29b-41d4-a716-446655440001', 'ml',
   'ബൈബിളിൽ ആത്മീയ സൗഹൃദം',
   'ബൈബിൾ ആഴമേറിയ സൗഹൃദത്തെ ദൈവത്തിന്റെ ഏറ്റവും വലിയ ദാനങ്ങളിലൊന്നായി ആഘോഷിക്കുന്നു — ദാവീദും യോനാഥാനും, രൂത്തും നവോമിയും, പൗലോസും തിമോഥെയോസും ഇതിന്റെ ഉദാഹരണങ്ങളാണ്. പരസ്പര പ്രതിബദ്ധത, സത്യസന്ധമായ ഉപദേശം, പങ്കുവയ്ക്കൽ, പ്രയാസ ഘട്ടങ്ങളിൽ ഉറച്ചുനിൽക്കുന്ന സ്നേഹം — ഇതാണ് ബൈബിൾ പറയുന്ന ആത്മീയ സൗഹൃദം. ആത്മീയ സൗഹൃദം ക്രിസ്തീയ ജീവിതത്തിന് ആഡംബരമല്ല, ആവശ്യമാണ് എന്ന് ഈ പഠനത്തിൽ നിങ്ങൾ പഠിക്കും.',
   'Church & Community'),

  ('aba00000-e29b-41d4-a716-446655440002', 'hi',
   'जवाबदेही और आपसी प्रोत्साहन',
   'इब्रानियों 10:24-25 विश्वासियों को एक-दूसरे को प्रेम और अच्छे कामों के लिए उकसाने की बुलाहट करता है। यही मसीही जवाबदेही का हृदय है — निगरानी नहीं बल्कि विश्वास में आपसी प्रोत्साहन। स्वस्थ जवाबदेही कैसी दिखती है, ईमानदार बातचीत कैसे करें, और छोटे समूह और शिष्यता संबंध कैसे एक फलते-फूलते मसीही जीवन की रीढ़ बनते हैं।',
   'Church & Community'),

  ('aba00000-e29b-41d4-a716-446655440002', 'ml',
   'ഉത്തരവാദിത്തവും പരസ്പര പ്രോത്സാഹനവും',
   'എബ്രായർ 10:24-25 വിശ്വാസികളെ സ്നേഹത്തിലും സൽപ്രവൃത്തികളിലും പരസ്പരം ഉത്തേജിപ്പിക്കാൻ വിളിക്കുന്നു. ഇതാണ് ക്രിസ്തീയ ഉത്തരവാദിത്തത്തിന്റെ ഹൃദയം — നിരീക്ഷണമല്ല, വിശ്വാസത്തിൽ പരസ്പരം ഉണർത്തൽ. ആരോഗ്യകരമായ ഉത്തരവാദിത്ത ബന്ധം എങ്ങനെ ഉണ്ടാകും, സത്യസന്ധമായ സംഭാഷണം എങ്ങനെ നടത്തണം, ചെറുകൂട്ടങ്ങളും ശിഷ്യത്വ ബന്ധങ്ങളും ഒരു ക്രിസ്തീയ ജീവിതത്തിന്റെ നട്ടെല്ലായി എങ്ങനെ മാറുന്നു എന്ന് ഈ പഠനം വ്യക്തമാക്കുന്നു.',
   'Church & Community')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- QQQ: Attributes of God (abb00000..001-004)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('abb00000-e29b-41d4-a716-446655440001', 'hi',
   'परमेश्वर पवित्र है',
   'पवित्रता परमेश्वर का परिभाषित स्वभाव है — स्वर्गदूतों का "पवित्र, पवित्र, पवित्र" पुकारना उनके बारे में कुछ आवश्यक पकड़ता है। परमेश्वर का बिल्कुल शुद्ध, अलग और नैतिक रूप से सिद्ध होने का क्या अर्थ है — और उनकी पवित्रता कैसे सब कुछ को आकार देती है: हमारी आराधना, नैतिकता, पाप की समझ और उनके सामने हमारी विस्मय को।',
   'Foundations of Faith'),

  ('abb00000-e29b-41d4-a716-446655440001', 'ml',
   'ദൈവം വിശുദ്ധനാണ്',
   'വിശുദ്ധി ദൈവത്തിന്റെ നിർണ്ണായക സ്വഭാവമാണ് — ദൂതന്മാരുടെ "പരിശുദ്ധൻ, പരിശുദ്ധൻ, പരിശുദ്ധൻ" എന്ന ആർപ്പ് അവനെ കുറിച്ചുള്ള ഒരു അടിസ്ഥാന സത്യം പിടിച്ചെടുക്കുന്നു. ദൈവം പൂർണ്ണമായും ശുദ്ധനും, വ്യത്യസ്തനും, ധാർമ്മികമായി സമ്പൂർണ്ണനും ആണ് എന്നതിന്റെ അർഥം ഈ പഠനത്തിൽ നാം മനസ്സിലാക്കുന്നു. അവന്റെ വിശുദ്ധി നമ്മുടെ ആരാധനയെ, നൈതികതയെ, പാപത്തെ കുറിച്ചുള്ള ഗ്രാഹ്യത്തെ, അവന്റെ മുന്നിൽ നമ്മുടെ വിസ്മയഭക്തിയെ എങ്ങനെ ആകാരപ്പെടുത്തുന്നു എന്നും ഇവിടെ ചർച്ച ചെയ്യുന്നു.',
   'Foundations of Faith'),

  ('abb00000-e29b-41d4-a716-446655440002', 'hi',
   'परमेश्वर प्रेम है और परमेश्वर न्यायी है',
   'ये दो स्वभाव अक्सर एक-दूसरे के विरुद्ध रखे जाते हैं, लेकिन शास्त्र उन्हें पूरी तरह एक साथ रखता है। परमेश्वर का प्रेम भावुक सहिष्णुता नहीं है — यह पवित्र, महँगा प्रेम है जो पाप को नज़रअंदाज़ नहीं करता। क्रूस वह जगह है जहाँ दोनों मिलते हैं: परमेश्वर का न्याय संतुष्ट, परमेश्वर का प्रेम उँडेला।',
   'Foundations of Faith'),

  ('abb00000-e29b-41d4-a716-446655440002', 'ml',
   'ദൈവം സ്നേഹമാണ്, ദൈവം നീതിമാനാണ്',
   'ഈ രണ്ട് സ്വഭാവങ്ങൾ പലപ്പോഴും പരസ്പരം വിരുദ്ധമായി ചിത്രീകരിക്കപ്പെടുന്നുണ്ടെങ്കിലും, തിരുവചനം അവ രണ്ടും ഒരുമിച്ച് ദൃഢമായി മുന്നോട്ടുവക്കുന്നു. ദൈവത്തിന്റെ സ്നേഹം വൈകാരിക സഹിഷ്ണുത മാത്രമല്ല — അത് പാപത്തെ അവഗണിക്കാത്ത, വിലകൊടുത്ത്, പരിശുദ്ധമായ സ്നേഹമാണ്. കുരിശ് ആ രണ്ടും സംഗമിക്കുന്ന ഇടമാണ്: ദൈവത്തിന്റെ നീതി നിറവേറ്റപ്പെടുന്നു, ദൈവത്തിന്റെ സ്നേഹം നമ്മിൽ ചൊരിയപ്പെടുന്നു. ഈ ആഴമേറിയ സത്യം ക്രിസ്തീയ ജീവിതത്തിന്റെ അടിത്തറയാണ്.',
   'Foundations of Faith'),

  ('abb00000-e29b-41d4-a716-446655440003', 'hi',
   'परमेश्वर प्रभु और सर्वज्ञ हैं',
   'परमेश्वर का प्रभुत्व — सारी सृष्टि पर उनका पूर्ण शासन — विश्वासी के लिए शास्त्र का सबसे सान्त्वना देने वाला सत्य है। परमेश्वर के सर्वज्ञ और सर्वशक्तिमान होने का क्या अर्थ है, उनका प्रभुत्व मानवीय स्वतंत्र इच्छा से कैसे संबंधित है, और सब कुछ पर उनके शासन पर भरोसा करना वास्तविक शांति की नींव क्यों है।',
   'Foundations of Faith'),

  ('abb00000-e29b-41d4-a716-446655440003', 'ml',
   'ദൈവം സർവ്വശക്തനും സർവ്വജ്ഞനുമാണ്',
   'ദൈവത്തിന്റെ പരമാധിപത്യം — സൃഷ്ടിയിൽ ഉടനീളമുള്ള അവന്റെ സമ്പൂർണ്ണ ഭരണം — ഒരു വിശ്വാസിക്ക് തിരുവചനത്തിലെ ഏറ്റവും ആശ്വാസം നൽകുന്ന സത്യമാണ്. ദൈവം സർവ്വജ്ഞനും സർവ്വശക്തനുമാണ് എന്നതിന്റെ അർഥം ഈ പഠനം അന്വേഷിക്കുന്നു. എല്ലാ കാര്യങ്ങളിലും അവന്റെ ഭരണത്തിൽ വിശ്വസിക്കുന്നത് ശരിയായ സമാധാനത്തിന്റെ അടിത്തറ ആകുന്നത് എന്തുകൊണ്ടാണ് എന്നും ഇവിടെ പഠിക്കാം.',
   'Foundations of Faith'),

  ('abb00000-e29b-41d4-a716-446655440004', 'hi',
   'परमेश्वर अनंत और अपरिवर्तनीय हैं',
   'परमेश्वर समय के बाहर विद्यमान हैं, उनका न आरंभ है न अंत, और उनका चरित्र कभी नहीं बदलता। परमेश्वर की अनंतता और अपरिवर्तनीयता के स्वभावों का अध्ययन करें और देखें ये सत्य क्यों गहरे महत्व रखते हैं: उनकी प्रतिज्ञाएँ कभी विफल नहीं होंगी, उनका प्रेम कभी कम नहीं होगा।',
   'Foundations of Faith'),

  ('abb00000-e29b-41d4-a716-446655440004', 'ml',
   'ദൈവം അനന്തനും മാറ്റമില്ലാത്തവനുമാണ്',
   'ദൈവം കാലത്തിന് അതീതനായി നിലനിൽക്കുന്നവനാണ്, അവനു ആരംഭവുമില്ല, അന്തവുമില്ല, അവന്റെ സ്വഭാവം ഒരിക്കലും മാറുകയുമില്ല. അവന്റെ വാഗ്ദത്തങ്ങൾ ഒരിക്കലും പരാജയപ്പെടുകയില്ല, അവന്റെ സ്നേഹം ഒരിക്കലും കുറയുകയില്ല, അവന്റെ ഉദ്ദേശ്യങ്ങൾ എന്നേക്കും ഉറച്ചുനിൽക്കും. ദൈവത്തിന്റെ ഈ മാറ്റമില്ലാത്ത സ്വഭാവം നമ്മുടെ ജീവിതത്തിലെ ഏത് അനിശ്ചിതത്വത്തിലും ഉറച്ച ആശ്രയം നൽകുന്നു.',
   'Foundations of Faith')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- RRR: Law, Grace, and the Covenants (abc00000..001-004)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('abc00000-e29b-41d4-a716-446655440001', 'hi',
   'व्यवस्था का उद्देश्य',
   'परमेश्वर ने व्यवस्था इस्राएल को बचाने के लिए नहीं दी — बल्कि अपने चरित्र को प्रकट करने, पाप को उजागर करने और अपनी प्रजा को उद्धारकर्ता की ज़रूरत दिखाने के लिए। शास्त्र में व्यवस्था के तीन उपयोग समझें — परमेश्वर की पवित्रता प्रकट करना, समाज में बुराई रोकना, और छुड़ाए गए लोगों को मार्गदर्शन देना।',
   'Foundations of Faith'),

  ('abc00000-e29b-41d4-a716-446655440001', 'ml',
   'ന്യായപ്രമാണത്തിന്റെ ഉദ്ദേശ്യം',
   'ദൈവം ന്യായപ്രമാണം ഇസ്രായേലിനെ രക്ഷിക്കാൻ നൽകിയതല്ല — പകരം അവന്റെ സ്വഭാവം വെളിപ്പെടുത്താനും, പാപം തുറന്നുകാണിക്കാനും, അവന്റെ ജനത്തിന് ഒരു രക്ഷകന്റെ ആവശ്യകത ബോധ്യപ്പെടുത്താനുമാണ്. ദൈവത്തിന്റെ വിശുദ്ധി വെളിപ്പെടുത്തുക, സമൂഹത്തിൽ തിന്മ തടയുക, വീണ്ടെടുക്കപ്പെട്ട ജനത്തെ നയിക്കുക — ഇതാണ് തിരുവചനം ന്യായപ്രമാണത്തിന് നൽകുന്ന മൂന്ന് ഉദ്ദേശ്യങ്ങൾ. ഈ പഠനം ന്യായപ്രമാണത്തിന്റെ ആഴം ഗ്രഹിക്കാൻ നമ്മെ സഹായിക്കും.',
   'Foundations of Faith'),

  ('abc00000-e29b-41d4-a716-446655440002', 'hi',
   'परमेश्वर की वाचाएँ',
   'परमेश्वर का मानवजाति के साथ संबंध वाचाओं के द्वारा संरचित है। प्रमुख बाइबलीय वाचाओं का अध्ययन करें: नूह, अब्राहम, मूसा, दाऊद के साथ वाचाएँ, और मसीह में नई वाचा। देखें कि कैसे हर वाचा परमेश्वर की छुटकारे की योजना को आगे बढ़ाती है और कैसे वे सब यीशु में अपनी पूर्ति पाती हैं।',
   'Foundations of Faith'),

  ('abc00000-e29b-41d4-a716-446655440002', 'ml',
   'ദൈവത്തിന്റെ ഉടമ്പടികൾ',
   'മനുഷ്യകുലത്തോടുള്ള ദൈവത്തിന്റെ ബന്ധം ഉടമ്പടികളിലൂടെ ഘടനാപ്പെടുത്തിയിരിക്കുന്നു. നോഹ, അബ്രഹാം, മോശ, ദാവീദ് എന്നിവരുമായുള്ള ഉടമ്പടികൾ, ക്രിസ്തുവിലൂടെ ഉള്ള പുതിയ ഉടമ്പടി — ഇവ ഈ പഠനം അന്വേഷിക്കുന്നു. ദൈവത്തിന്റെ വീണ്ടെടുപ്പ് പദ്ധതി ഓരോ ഉടമ്പടിയിലൂടെ മുന്നോട്ട് നീങ്ങി, ആ ഉടമ്പടികൾ ഒടുവിൽ യേശുവിൽ പൂർത്തിയാകുന്ന വിധം ഇവിടെ കാണാം.',
   'Foundations of Faith'),

  ('abc00000-e29b-41d4-a716-446655440003', 'hi',
   'मसीह में नई वाचा',
   'यिर्मयाह ने एक नई वाचा की भविष्यवाणी की जहाँ परमेश्वर का नियम पत्थर की पट्टियों पर नहीं बल्कि हृदयों पर लिखा जाएगा — और यीशु ने इसे अंतिम भोज में अपने लहू से शुरू किया। नई वाचा का क्या अर्थ है: पूर्ण क्षमा, वास करने वाला आत्मा, परमेश्वर तक सीधी पहुँच, और एक बदला हुआ हृदय।',
   'Foundations of Faith'),

  ('abc00000-e29b-41d4-a716-446655440003', 'ml',
   'ക്രിസ്തുവിലെ പുതിയ ഉടമ്പടി',
   'ദൈവത്തിന്റെ ന്യായപ്രമാണം ഹൃദയങ്ങളിൽ എഴുതപ്പെടുന്ന ഒരു പുതിയ ഉടമ്പടി യിരെമ്യാ പ്രവചിച്ചു — അന്ത്യ അത്താഴത്തിൽ യേശു തന്റെ രക്തത്താൽ അത് ആരംഭിച്ചു. പൂർണ്ണ ക്ഷമ, വസിക്കുന്ന ആത്മാവ്, ദൈവത്തിലേക്ക് നേരിട്ടുള്ള പ്രവേശനം, ഒരു പുതുക്കപ്പെട്ട ഹൃദയം — ഇതാണ് പുതിയ ഉടമ്പടിയുടെ അർഥം. ഈ ഉടമ്പടി ക്രിസ്തുവിൽ വിശ്വസിക്കുന്ന ഓരോ വ്യക്തിക്കും ദൈവം വ്യക്തിപരമായി നൽകുന്ന ഒരു വാഗ്ദത്തമാണ്.',
   'Foundations of Faith'),

  ('abc00000-e29b-41d4-a716-446655440004', 'hi',
   'व्यवस्था के अधीन नहीं, अनुग्रह के अधीन',
   'रोमियों 6:14 घोषणा करता है कि विश्वासी व्यवस्था के अधीन नहीं बल्कि अनुग्रह के अधीन हैं। पौलुस का क्या अर्थ है, अनुग्रह अनैतिकता की ओर नहीं बल्कि बदली आज्ञाकारिता की ओर कैसे ले जाता है, और विश्वासी आत्मा के द्वारा डाले गए प्रेम से व्यवस्था की भावना को कैसे पूरा करते हैं।',
   'Foundations of Faith'),

  ('abc00000-e29b-41d4-a716-446655440004', 'ml',
   'ന്യായപ്രമാണത്തിൻ കീഴിലല്ല, കൃപയ്ക്കു കീഴിൽ',
   'റോമർ 6:14 പ്രഖ്യാപിക്കുന്നത്, വിശ്വാസി ന്യായപ്രമാണത്തിൻ കീഴിലല്ല, കൃപയ്ക്കു കീഴിലാണ് എന്നാണ്. കൃപ അധർമ്മത്തിലേക്ക് നയിക്കുന്നില്ല, മറിച്ച് പരിവർത്തനപ്പെട്ട അനുസരണത്തിലേക്ക് നയിക്കുന്നു. വിശ്വാസി ആത്മാവിനാൽ ന്യായപ്രമാണത്തിന്റെ ആത്മാവ് നിറവേറ്റുന്നു. കൃപ പരിശുദ്ധ ജീവിതത്തിന്റെ ശക്തിയാണ്, പാപത്തിന് ലൈസൻസ് അല്ല — ഇതാണ് ഈ പഠനത്തിന്റെ കാതൽ.',
   'Foundations of Faith')

ON CONFLICT (topic_id, language_code) DO NOTHING;

-- -------------------------------------------------------
-- SSS: Sin, Repentance, and Grace (abd00000..001-002)
-- -------------------------------------------------------
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES

  ('abd00000-e29b-41d4-a716-446655440001', 'hi',
   'पाप की प्रकृति और मज़दूरी',
   'पाप केवल नियम तोड़ना नहीं है — यह सृजनहार के विरुद्ध सृजित का मूलभूत विद्रोह है। पाप की बाइबलीय परिभाषा, मूल पाप और उसका सारी मानवजाति पर प्रभाव, और शास्त्र का क्या अर्थ है जब वह कहता है कि पाप की मज़दूरी मृत्यु है। यह ज्ञान कुचलने के लिए नहीं — बल्कि हमें मसीह की ओर ले जाने के लिए है।',
   'Foundations of Faith'),

  ('abd00000-e29b-41d4-a716-446655440001', 'ml',
   'പാപത്തിന്റെ സ്വഭാവവും കൂലിയും',
   'പാപം കേവലം ഒരു നിയമം ലംഘിക്കലല്ല — അത് സ്രഷ്ടാവിനെതിരെ സൃഷ്ടിയുടെ മൗലിക കലാപമാണ്. പാപത്തിന്റെ ബൈബിൾ നിർവ്വചനം, ആദ്യ പാപം സകല മനുഷ്യകുലത്തെയും ബാധിക്കുന്ന വിധം, പാപത്തിന്റെ കൂലി മരണം എന്ന് തിരുവചനം പഠിപ്പിക്കുന്നതിന്റെ അർഥം — ഇവ ഈ പഠനം ചർച്ച ചെയ്യുന്നു. ഈ അറിവ് നമ്മെ തകർക്കാനല്ല — ക്രിസ്തുവിലേക്ക് നയിക്കാനാണ്.',
   'Foundations of Faith'),

  ('abd00000-e29b-41d4-a716-446655440002', 'hi',
   'सच्चा पश्चाताप बनाम केवल अफ़सोस',
   '2 कुरिन्थियों 7:10 ईश्वरीय दुख को अलग करता है जो पश्चाताप की ओर ले जाता है — सांसारिक दुख से जो मृत्यु की ओर ले जाता है। सच्चा पश्चाताप केवल बुरा महसूस करना नहीं है — यह पाप से मुड़ना और परमेश्वर की ओर मुड़ना है। वास्तविक पश्चाताप के चिह्न, यह अफ़सोस, दोष प्रबंधन या व्यवहार परिवर्तन से कैसे अलग है।',
   'Christian Living'),

  ('abd00000-e29b-41d4-a716-446655440002', 'ml',
   'യഥാർഥ പശ്ചാത്താപം, കേവലം ഖേദം മാത്രമല്ല',
   '2 കൊരിന്ത്യർ 7:10 ദൈവഭക്തിയുള്ള ദുഃഖത്തെ — പശ്ചാത്താപത്തിലേക്ക് നയിക്കുന്ന ദുഃഖത്തെ — ലൗകിക ദുഃഖത്തിൽ നിന്ന് — മരണത്തിലേക്ക് നയിക്കുന്ന ദുഃഖത്തിൽ നിന്ന് — വ്യക്തമായി വേർതിരിക്കുന്നു. യഥാർഥ പശ്ചാത്താപം കേവലം ദുഃഖം അനുഭവിക്കലല്ല — അത് പാപത്തിൽ നിന്ന് തിരിഞ്ഞ് ദൈവത്തിലേക്ക് മടങ്ങലാണ്. ശരിയായ പശ്ചാത്താപത്തിന്റെ അടയാളങ്ങൾ ഏവ, അത് കേവലം ഖേദത്തിൽ നിന്ന് എങ്ങനെ വ്യത്യാസപ്പെടുന്നു — ഇത് ഈ പഠനം വ്യക്തമാക്കുന്നു.',
   'Christian Living')

